INSERT INTO public.photos VALUES (21371, 'Sal‚îú‚îÇn Fuenclara c.1915', '"Retrato de grupo de ni‚îú‚ñías disfrazadas en el Patio de luces del cine Fuenclara". El cine Fuenclara (calle Fuenclara, 2) comenz‚îú‚îÇ a funcionar en 1915 en lo que hasta entonces hab‚îú¬°a sido teatro ("Sal‚îú‚îÇn Fuenclara"), con capacidad para unas 500 personas. Las sesiones infantiles, como la de la imagen, eran a las 17 h., en funciones organizadas por las "Escuelas Dominicales", a cargo de las Se‚îú‚ñíoritas Instructoras. Tras la proclamaci‚îú‚îÇn de la Segunda Rep‚îú‚ïëblica democr‚îú√≠tica espa‚îú‚ñíola, en el sal‚îú‚îÇn del teatro tuvieron lugar m‚îú¬°tines y actos pol‚îú¬°ticos de "afirmaci‚îú‚îÇn cat‚îú‚îÇlica", como el que tuvo lugar el 9 de noviembre de ese a‚îú‚ñío. Desde la venida de la columna, en m‚îú√≠rmol mortal, la religi‚îú‚îÇn cat‚îú‚îÇlica y la pol‚îú¬°tica nunca han dejado de ir de la mano en esta ciudad, con todo lo que ello implica. En la d‚îú¬Æcada siguiente, antes de convertirse en cine, continu‚îú‚îÇ siendo utilizado como local de teatro, por ejemplo, por la Asociaci‚îú‚îÇn de los J‚îú‚îÇvenes de Acci‚îú‚îÇn Cat‚îú‚îÇlica (Centro de la Seo), en horario ya no tan infantil (22.00 h). Fuente visual: Archivo Municipal. Francisco G‚îú‚îÇrriz (Donaci‚îú‚îÇn Palacio Fuenclara).', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65394400, -0.88230200, '0101000020E6100000A7406667D13BECBF2DB5DE6FB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15420945139.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15420945139.webp', 'https://www.flickr.com/photos/zaragozaantigua/15420945139/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21456, 'Palacio de Fuenclara 1918', '"Reparto de comida a los pobres y obreros sin trabajo, de los cuales socorre diariamente m‚îú√≠s de mil esta benem‚îú¬Ærita entidad". Escena situada en el patio de la casa de Fuenclara, acondicionada por el arzobispado en 1899 como sede de la Sociedad Protectora de J‚îú‚îÇvenes Obreros y Comerciantes.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65401400, -0.88212300, '0101000020E6100000C09481035A3AECBF259012BBB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52021455349.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52021455349.webp', 'https://www.flickr.com/photos/zaragozaantigua/52021455349/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21611, 'Sal‚îú‚îÇn Fuenclara c.1925', 'Imagen capturada en el interior del teatro Sal‚îú‚îÇn Fuenclara dise‚îú‚ñíado por el arquitecto Francisco Albi‚îú‚ñíana en la antigua casa de los condes de Fuenclara, sita en el n‚îú‚ïëmero 2 de la hom‚îú‚îÇnima calle. Inaugurado en 1914 y gestionado por la cat‚îú‚îÇlica Sociedad Protectora de J‚îú‚îÇvenes Obreros y Comerciantes, desde 1951 se dedicar‚îú¬°a exclusivamente a la exhibici‚îú‚îÇn de pel‚îú¬°culas ya como Cine Arlequ‚îú¬°n. Fuente visual: Francisco G‚îú‚îÇrriz, AMZ.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65401400, -0.88212300, '0101000020E6100000C09481035A3AECBF259012BBB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30440832188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30440832188.webp', 'https://www.flickr.com/photos/zaragozaantigua/30440832188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21853, 'Calle de M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez 1931', 'Imagen de la esquina de la calle de M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez con la del Pino (hacia la derecha) y con la de las V‚îú¬°rgenes (hacia la izquierda), ubicaci‚îú‚îÇn desde finales del siglo XVI del Colegio de las V‚îú¬°rgenes, en la entonces calle de las Botigas Hondas. Entre 1853 y 1873 fue sede del Teatro Variedades. En el momento de realizar la foto era propiedad de Narciso Alfonso. Hacia 1943 el edificio, que conservaba retazos de su pasado conventual y teatral, fue derribado a finales de 1946 y sobre su solar se construyeron modernos bloques de vivienda. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65411000, -0.88027800, '0101000020E6100000DB6CACC43C2BECBF48FE60E0B9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35806169953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35806169953.webp', 'https://www.flickr.com/photos/zaragozaantigua/35806169953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22052, 'Pl. de San Felipe 1959', 'La plaza de San Felipe en una vista de su lado oeste comprendido entre la hom‚îú‚îÇnima iglesia parroquial, a la izquierda, y la calle de la Torre Nueva a la derecha. Destaca la fachada de la gran casa del siglo XVI que fuera de los Sanz de Cort‚îú¬Æs, luego de los marqueses de Villaverde, y ya en el siglo XIX de la condesa de Argillo. Tras pasar por diversas situaciones y usos, en esta fotograf‚îú¬°a el edificio era compartido por la delegaci‚îú‚îÇn provincial de la Organizaci‚îú‚îÇn Nacional de Ciegos (establecida en 1958) y el veterano Colegio de San Felipe. Esta plaza y su entorno estaban tambi‚îú¬Æn caracterizados por su destacado car‚îú√≠cter comercial. Fuente visual: Archivo Mora, en AMZ.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65473900, -0.88207900, '0101000020E6100000D7A02FBDFD39ECBF3735D07CCED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14897861907.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14897861907.webp', 'https://www.flickr.com/photos/zaragozaantigua/14897861907/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22069, 'Calle de Gil Berges 1953', 'Los Cabezudos Morico, Forano y Verrug‚îú‚îÇn comparsean la calle en el tranquilo tramo de los peques viviendo desde la calle Fuenclara (al fondo, a la izquierda). La imagen ha sido tomada en la calle Gil Berges, camino de la plaza de San Felipe. A la derecha, el callej‚îú‚îÇn de Torresecas. Gr‚îú√≠ficas Minerva, esquina la manzana del Palacio de Fuenclara. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65427600, -0.88227500, '0101000020E61000004182E2C7983BECBF6347E350BFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15180921100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15180921100.webp', 'https://www.flickr.com/photos/zaragozaantigua/15180921100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22119, 'Florencio Mercadal 1956', 'Foto: Miguel Mar‚îú¬°n Chivite. Imagen del ‚îú‚ïëltimo pajarero con puesto fijo en las calles de Zaragoza, Florencio Mercadal, en mayo de 1956. Estuvo vendiendo p‚îú√≠jaros en la plaza de Sas entre 1949 y, al menos, 1967. Vend‚îú¬°a canarios, periquitos, cardelinos y verderones, adem‚îú√≠s de conejos de Indias, gatos y perros. Fuente: Heraldo de Arag‚îú‚îÇn.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65408300, -0.88101000, '0101000020E6100000E15D2EE23B31ECBF4EEFE2FDB8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22500992376.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22500992376.webp', 'https://www.flickr.com/photos/zaragozaantigua/22500992376/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22123, 'San Felipe c.1950', 'Plaza e iglesia parroquial de San Felipe. Detalle de la portada barroca. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65454000, -0.88215800, '0101000020E6100000DCF3FC69A33AECBF40F67AF7C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22753564077.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22753564077.webp', 'https://www.flickr.com/photos/zaragozaantigua/22753564077/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22133, 'Calle Agustines 1951', 'Imagen capturada en la calle Fuenclara de una notable confluencia de viales: a la izquierda, la calle de Torresecas, medieval trenque abierto al Coso, luego cerrado, cuyo nombre proviene de la sobresaliente Casa de los Condes de Torres Secas, all‚îú¬° ubicada hasta su derribo. Al frente, el final de la calle de Agustines, que viene de la calle de la Audiencia, al fondo, antigua Subida de los Gigantes desde el Coso (otro trenque de la antigua muralla); a la derecha, la culminaci‚îú‚îÇn de la calle Gil Berges, que viene desde la plaza de San Felipe. Inmediata, a la izquierda, la esquina del antiguo palacio de Fuenclara a la calle Torresecas, que acog‚îú¬°a en sus bajos a la imprenta "Gr‚îú√≠ficas Minerva", junto a la "Farmacia Lasala", y a la "Librer‚îú¬°a Libros". Al otro lado de la calle, el nov‚îú¬°simo y chaflanero edificio del 6 de Agustines, entre la calle Torresecas y la desaparecida calle del Vicario. A la derecha, la esquinera casona del n‚î¨‚ïë 5 entre Gil Berges y Agustines, en cuyos bajos estaba la "Bola de Plata". En la calle Agustines, un pil‚îú‚îÇn de piedra disuasorio del paso de veh‚îú¬°culos. En la esquina de Gil Berges, un pil‚îú‚îÇn esquinero como defensa ante veh‚îú¬°culos. Fuente visual: Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65418200, -0.88245600, '0101000020E61000005516855D143DECBFE1D05B3CBCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23972032124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23972032124.webp', 'https://www.flickr.com/photos/zaragozaantigua/23972032124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22135, 'Calle Gil Berges 1951', 'La calle de Gil Berges form‚îú‚îÇ parte hasta bien entrado el siglo XX de la plaza de San Felipe, desde donde se ha tomado esta fotograf‚îú¬°a. A la izquierda, la manzana entre las calles de Candalija (antigua de Montera) y de Fuenclara, donde destaca el establecimiento comercial Pa‚îú‚ñíos Sesma, que perdur‚îú‚îÇ hasta el siglo siguiente. Al fondo, la calle de Fuenclara y el hom‚îú‚îÇnimo palacio con la imprenta Gr‚îú√≠ficas Minerva en sus bajos. A continuaci‚îú‚îÇn, el callej‚îú‚îÇn de Torresecas, y a la derecha la irregular manzana de casonas entre las calles de Agustines y de Morata, en cuya esquina tuvo su primera sede la imprenta de Tom‚îú√≠s Blasco. Fuente visual: Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65433400, -0.88228400, '0101000020E61000000D17B9A7AB3BECBF97546D37C1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23974446423.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23974446423.webp', 'https://www.flickr.com/photos/zaragozaantigua/23974446423/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22307, 'Torre‚îú‚îÇn Fortea 1965', 'Archivo Municipal. Gerardo Sancho Ramo. 1965. "Iglesia de San Felipe, Torre‚îú‚îÇn Fortea y Museo de Pablo Gargallo". Imagen centrada en el macizo Torre‚îú‚îÇn Fortea. A la izquierda, la iglesia de San Felipe primero, y luego el Palacio de los Condes de Argillo, entonces sede del Colegio de San Felipe, y actual Museo de Pablo Gargallo (oculto tras la iglesia en la foto).', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65468300, -0.88206900, '0101000020E6100000F4177AC4E839ECBFA31F0DA7CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15642353835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15642353835.webp', 'https://www.flickr.com/photos/zaragozaantigua/15642353835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22318, 'Calle de Alfonso I 1968', 'Imagen del esplendor glorioso de una abundante iluminaci‚îú‚îÇn decorativa de esas que se instalan durante unas fechas muy se‚îú‚ñíaladas del calendario, entre diciembre y enero. Esta decoraci‚îú‚îÇn lum‚îú¬°nica parece obrar sobre los humanos el efecto de la fototaxia en su versi‚îú‚îÇn consumista, pues suele aparecen sospechosamente en aquellas calles o zonas destacadas por su vertiente comercial, al efecto de inducir de forma sibilina a dejarse llevar por los insinuantes escaparates. Como se ve, a estas horas de la noche el ‚îú¬Æxito es arrollador, y no queda nadie en la calle, porque todos est‚îú√≠n dentro de los comercios comprando felicidad, y regando los brotes verdes de la macroeconom‚îú¬°a. O a lo mejor no hay nadie, y es un soberano despilfarro. Eso s‚îú¬°, precioso. Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65458900, -0.88061200, '0101000020E610000086E28E37F92DECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15849888296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15849888296.webp', 'https://www.flickr.com/photos/zaragozaantigua/15849888296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22360, 'Gran Turismo 1967', 'Parada de taxis Gran Turismo en la plaza Sas. Se trataba de autom‚îú‚îÇviles de alquiler de alta gama, que no llevaban tax‚îú¬°metro y se sol‚îú¬°an usar para bodas, celebraciones y viajes.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65398600, -0.88091300, '0101000020E610000043E1B3757030ECBF5C0531D0B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21026402504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21026402504.webp', 'https://www.flickr.com/photos/zaragozaantigua/21026402504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22505, 'Calle de Alfonso I 1964', 'Estival imagen capturada desde la altura del inmueble del n‚î¨‚ïë 12 de la calle de Alfonso I, donde estaba ubicado el estudio fotogr‚îú√≠fico de Coyne, y centrada en el paso del cortejo oficial y tradicionalista encabezado, sobre mula blanca, por Pedro Cantero Cuadrado durante el ceremonial de toma de posesi‚îú‚îÇn como nuevo arzobispo de Zaragoza el d‚îú¬°a 16 de julio de 1964. Unos golpes de pezu‚îú‚ñía antes y a caballo, el alcalde Luis G‚îú‚îÇmez Laguna. En primer t‚îú¬Ærmino, fila de miembros de la Corporaci‚îú‚îÇn municipal, y a ambos lados del vial, numeroso p‚îú‚ïëblico asistente, mientras vuelan miles de papelillos al sofocante aire arrojados fervorosa y organizadamente. De fondo, publicidad varia adosada a las vallas que delimitan el solar donde estuviera el antiguo inmueble del n‚î¨‚ïë 17, esquinero con los n‚îú‚ïëmeros 5, 7 y 9 de la calle de Fuenclara, derribado pocos meses antes para embellecer este tramo de la calle.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65385100, -0.88137300, '0101000020E6100000207A52263534ECBF7CBABA63B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50135958963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50135958963.webp', 'https://www.flickr.com/photos/zaragozaantigua/50135958963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22543, 'Joyer‚îú¬°a Aladr‚îú¬Æn c.1976', 'Foto Gonzalo Bull‚îú‚îÇn. Sucesor Joyer‚îú¬°a Aladr‚îú¬Æn (Jos‚îú¬Æ Lacruz L‚îú‚îÇpez). Tienda en Alfonso I n‚î¨‚ïë 25, declarada Bien de Inter‚îú¬Æs Cultural, Gran Caf‚îú¬Æ Zaragoza desde septiembre de 1998. Fuente: www.rafaelcastillejo.com', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65467700, -0.88058600, '0101000020E61000003718EAB0C22DECBFC138B874CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14939687490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14939687490.webp', 'https://www.flickr.com/photos/zaragozaantigua/14939687490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22552, 'Pl. de San Felipe c.1977', 'Desde 1860, el palacio de Argillo acogi‚îú‚îÇ en alquiler al Colegio de San Felipe. En 1943, el palacio fue declarado Monumento Nacional y, desde 1946, cambi‚îú‚îÇ de propietario y uso. La Organizaci‚îú‚îÇn Nacional de Ciegos Espa‚îú‚ñíoles comparti‚îú‚îÇ espacios con el Colegio de San Felipe (trasladado en 1958). En 1970, la ONCE cambiaba tambi‚îú¬Æn de domicilio. En 1977 el Ayuntamiento de Zaragoza efectu‚îú‚îÇ la adquisici‚îú‚îÇn del edificio. Al tratarse de un Monumento Nacional, el Ministerio de Cultura financi‚îú‚îÇ algunas intervenciones de consolidaci‚îú‚îÇn para frenar su progresiva ruina. En 1979 se firm‚îú‚îÇ un convenio entre el Ministerio y el Ayuntamiento, encaminado a restaurar el edificio y utilizarlo como sede para talleres art‚îú¬°sticos. En la imagen, aspecto de la Plaza de San Felipe en las inmediaciones del Palacio de Argillo, a la derecha, y de la Iglesia de San Felipe, al fondo.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65480000, -0.88237200, '0101000020E6100000DFFE5C34643CECBFDDB5847CD0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15028653690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15028653690.webp', 'https://www.flickr.com/photos/zaragozaantigua/15028653690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22660, 'Plaza San Felipe 1977', 'Plaza e iglesia parroquial de San Felipe. A la izquierda, la calle Gil Berges. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65454000, -0.88215800, '0101000020E6100000DCF3FC69A33AECBF40F67AF7C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22523851803.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22523851803.webp', 'https://www.flickr.com/photos/zaragozaantigua/22523851803/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22741, 'Calle de Alfonso I 1979', 'Vista de la calle de Alfonso I desde su esquina con la plaza de Sas (izquierda). Al fondo, el Coso Alto. A la derecha, grandes almacenes Gay, tras el Hotel Europa. Fuente: Heraldo de Arag‚îú‚îÇn.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.65403600, -0.88129800, '0101000020E610000077F700DD9733ECBF0D349F73B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31652079893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31652079893.webp', 'https://www.flickr.com/photos/zaragozaantigua/31652079893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22856, 'Gil Berg‚îú¬Æs A‚îú‚ñíos 80', 'Imagen del peque‚îú‚ñío edificio de vivienda (antiguo n‚î¨‚ïë 5, luego n‚î¨‚ïë 1) que hac‚îú¬°a esquina entre las calles de Gil Berges y la de Agustines, cerca de la plaza de San Felipe. Construido en arquitectura tradicional, como la de otros edificios de la zona, es muy probable que su original planta fuera del XVII, con remodelaciones posteriores. Presentaba una interesante galer‚îú¬°a de arquillos, o mirador, bajo alero o cornisa. A diferencia de esos otros edificios, ‚îú¬Æste fue piqueteado en 1997, y en su lugar hay desde entonces un solar. En la imagen, dibujo recreando el edificio, cuando en sus bajos acog‚îú¬°a un negocio de solera: la churrer‚îú¬°a "Bola de Plata". Fuente: www.facebook.com/photo.php?fbid=600342463428476&set=p...', 1980, 1980, 1989, 'Anos 80', 'CENTRO', 41.65426800, -0.88253200, '0101000020E6100000158DB5BFB33DECBFE068C70DBFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15601187499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15601187499.webp', 'https://www.flickr.com/photos/zaragozaantigua/15601187499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22861, 'Torre‚îú‚îÇn Fortea 1987', 'Luis M‚îú¬°nguez. 1987. Desde la singular torre de iglesia de San Felipe, esquivando levemente la oscura campana, un vistazo hacia el Norte, en la medida de lo posible. En primer plano, la vegetaci‚îú‚îÇn de la inmediata plaza de San Felipe, y el macizo torre‚îú‚îÇn Fortea, a la izquierda. Por uno de sus vanos nos podemos trasladar hasta el otro lado del Ebro, y llegar a Valle de Broto (la calle). A la derecha, la torre de Santiago de la bas‚îú¬°lica del Pilar.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65454900, -0.88237100, '0101000020E6100000C80A7E1B623CECBF9450FA42C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15656533430.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15656533430.webp', 'https://www.flickr.com/photos/zaragozaantigua/15656533430/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22868, 'Torre Nueva 1989', 'Imagen del pie de la Torre Nueva de Zaragoza, sacado a la luz en las excavaciones arqueol‚îú‚îÇgicas realizadas en 1988 y 1989.', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15750348182.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15750348182.webp', 'https://www.flickr.com/photos/zaragozaantigua/15750348182/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22944, 'Pl. de San Felipe 1987', 'Foto: Tom‚îú√≠s Mora Ruata. Vista de la plaza de San Felipe en 1987. A la derecha, obras de restauraci‚îú‚îÇn del Torre‚îú‚îÇn Fortea, antigua casa de los Cerd‚îú√≠n de Escatr‚îú‚îÇn, adquirida por el Ayuntamiento en 1981. En 1991 se remodelar‚îú√≠ la plaza. Fuente: www.facebook.com/photo.php?fbid=1810357708992339&set=...', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65472200, -0.88213500, '0101000020E6100000D105F52D733AECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36622101730.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36622101730.webp', 'https://www.flickr.com/photos/zaragozaantigua/36622101730/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22979, 'Memorial de la Torre Nueva c.1995', 'El monumento que preside la foto, levantado sobre el per‚îú¬°metro original de la Torre Nueva de Zaragoza en la plaza de San Felipe, junto al Torre‚îú‚îÇn Fortea, fue erigido en 1991, al acometer el Ayuntamiento la remodelaci‚îú‚îÇn de la plaza. En marzo de 2002 fue derribado. Queda en el suelo el recuerdo de la forma del s‚îú‚îÇtano de la torre, seg‚îú‚ïën la excavaci‚îú‚îÇn arqueol‚îú‚îÇgica. Tambi‚îú¬Æn, a su lado, la estatua sedente en bronce de un ni‚îú‚ñío que mira hacia lo alto del fantasma del antiguo campanario civil exento. Fuente visual: www.placesonline.es/europa/espana/aragon/zaragoza/detalle...', 1995, 1995, 1995, 'Anos 90', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15697777472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15697777472.webp', 'https://www.flickr.com/photos/zaragozaantigua/15697777472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22995, 'Calle de Alfonso I 1992', 'El n‚î¨‚ïë 18 de la calle Alfonso I, construido a la par que el n‚î¨‚ïë 20, y recayente a la calle M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez, forma parte de las nuevas construcciones a la carta realizadas para adaptarse a los gustos ecl‚îú¬Æcticos de la nueva y burguesa calle. A mediados de los a‚îú‚ñíos 20 del pasado siglo, su planta baja, a la izquierda del portal de ingreso, fue acondicionada para la "Librer‚îú¬°a y Papeler‚îú¬°a Aperte", resultando uno de los locales comerciales m‚îú√≠s interesantes de la ciudad por su infrecuente traza racionalista con decoraciones "art d‚îú¬Æco". Madera, vidrier‚îú¬°a, rejer‚îú¬°a, y m‚îú√≠rmoles, compon‚îú¬°an una singular fachada, acompa‚îú‚ñíada en el interior de una decoraci‚îú‚îÇn y mobiliario congruentes. En 1993, la firma comercial "Aperte" cerr‚îú‚îÇ, y el local fue remodelado a los gustos postmodernos de la ‚îú¬Æpoca, resultando lo que hoy hay en su lugar, en tono banana. La imagen captura el estado del local, antes de su transfiguraci‚îú‚îÇn.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65445500, -0.88066400, '0101000020E61000002577D844662EECBF12DA722EC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23118237906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23118237906.webp', 'https://www.flickr.com/photos/zaragozaantigua/23118237906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22999, 'Pasaje de los Giles a‚îú‚ñíos 90', 'Vista del interior del Pasaje de los Giles a finales del siglo XX. Este espacio fue cerrado poco despu‚îú¬Æs de ser tomada la imagen y reabierto ya en el siglo XXI. La terraza hostelera corresponde a la Horchater‚îú¬°a Miguel, enclavada en la entrada del pasaje por la calle de los Est‚îú¬Æbanes (al fondo a la derecha).', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65371400, -0.88070900, '0101000020E6100000245F09A4C42EECBFFB777DE6ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26437747201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26437747201.webp', 'https://www.flickr.com/photos/zaragozaantigua/26437747201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23013, 'Torre Nueva 1991', 'El Ayuntamiento de la ciudad aprob‚îú‚îÇ en 1990 un proyecto de Memorial o monumento conmemorativo de la Torre Nueva a construir en la plaza de San Felipe, consistente en el recrecimiento parcial en ladrillo del n‚îú‚ïëcleo interior de la Torre Nueva, con un remate en forma helicoidal e inacabada que remarcaba el derribo padecido en 1892. Adem‚îú√≠s, unos paneles de albino m‚îú√≠rmol de Macael perfilaban la planta estrellada que caracterizaba el arranque de la Torre. Entre dos de esos paneles fueron colocadas unas puertas de bronce con un alto relieve de la Torre, y una inscripci‚îú‚îÇn informativa. Desencuentros administrativos producidos entre el Ayuntamiento y la Direcci‚îú‚îÇn General de Patrimonio Cultural y Educaci‚îú‚îÇn de la DGA, desde el principio mismo del proyecto, desembocaron en un largo proceso judicial que culmin‚îú‚îÇ en la Sentencia 388/1998 del Tribunal Superior de Justicia de Arag‚îú‚îÇn, que declaraba la ilegalidad de las obras ejecutadas e inauguradas en 1991, se‚îú‚ñíalando que habr‚îú¬°an de demolerse por perturbar la contemplaci‚îú‚îÇn de bienes de Inter‚îú¬Æs Cultural como el Torre‚îú‚îÇn Fortea. En marzo de 2002 la referida Sentencia fue cumplida, y se procedi‚îú‚îÇ a la demolici‚îú‚îÇn del Memorial. En la imagen, puertas de bronce del Memorial de la Torre Nueva, inaugurado en 1991 y demolido por Sentencia en 2002, si bien perdura el bronc‚îú¬°neo "mir‚îú‚îÇn" dise‚îú‚ñíado por Santiago Gimeno Llop que en la plaza de San Felipe mantiene la vista, de forma perenne, en el ectoplasma de la desaparecida Torre Nueva de Zaragoza. La figura de la Torre se corresponde con la etapa en que estaba coronada por un triple chapitel barroco, instalado en 1749 y desmontado en 1878 como paso previo a la demolici‚îú‚îÇn de 1892. Es la imagen "cl‚îú√≠sica" de esta singular y perdida atalaya urbana. Fuente visual: revista "Arag‚îú‚îÇn tur‚îú¬°stico y monumental", SIPA.', 1991, 1991, 1991, 'Anos 90', 'CENTRO', 41.65488800, -0.88204800, '0101000020E6100000171230BABC39ECBF7C45B75ED3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34058280224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34058280224.webp', 'https://www.flickr.com/photos/zaragozaantigua/34058280224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23028, 'Plaza de San Felipe 1992', 'A finales de los a‚îú‚ñíos ochenta el Ayuntamiento impuls‚îú‚îÇ el plan "Zaragoza 1992" que incluy‚îú‚îÇ actuaciones en el casco hist‚îú‚îÇrico para rehabilitar su imagen al hilo del evento que conmemoraba el quinto centenario de 1492. De esta forma, varias plazas, entre ellas la de San Felipe, fueron objeto de una intervenci‚îú‚îÇn urban‚îú¬°stica para renovar su aspecto, que en este caso incluy‚îú‚îÇ el Memorial de la Torre Nueva complementado de forma no prevista por el bronce titulado Muchacho sentado mirando a la Torre Nueva, y otros motivos simb‚îú‚îÇlicos y gr‚îú√≠ficos asociados al recuerdo de esta referencial atalaya derribada a finales del siglo XIX. Una orden judicial supuso la eliminaci‚îú‚îÇn del memorial en 2002, y el vandalismo urbano acab‚îú‚îÇ con los motivos simb‚îú‚îÇlicos y gr‚îú√≠ficos, dejando "colgada" a la escultura realizada por Santiago Gimeno Llop que, en estas circunstancias, dirige su mirada hacia el espacio que ocupaba la Torre Nueva, aunque por supuesto no hay ninguna referencia que lo explique para quien se tope literalmente con ella. En la imagen, aspecto de la plaza tras su renovaci‚îú‚îÇn y en un d‚îú¬°a lluvioso, con el fondo de la iglesia de San Felipe, el palacio de Argillo, el Memorial de la Torre Nueva observado por el bronc‚îú¬°neo muchacho sentado en el suelo, y la casa-torre‚îú‚îÇn de los Fortea.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65465300, -0.88203900, '0101000020E61000004A7D59DAA939ECBF399D64ABCBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50204841172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50204841172.webp', 'https://www.flickr.com/photos/zaragozaantigua/50204841172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23030, 'Calle de Alfonso I 1992', 'Calle de Alfonso I, en una vista tomada a la altura de la de Casto M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez, a la derecha. La configuraci‚îú‚îÇn de este vial todav‚îú¬°a est‚îú√≠ preparada para el tr‚îú√≠fico rodado, con dos carriles de circulaci‚îú‚îÇn. En el firme, las indicaciones llevan a continuar hasta la plaza del Pilar, o a girar a la izquierda por la calle de la Torre Nueva hasta el Mercado Central. En 2001, esta calle comercial ser‚îú√≠ remodelada y peatonalizada.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65433900, -0.88091200, '0101000020E61000002DEDD45C6E30ECBFA9BF5E61C1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207270752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207270752.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207270752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23097, 'Calle de Alfonso I 2000', 'Aspecto de la manifestaci‚îú‚îÇn contra el trasvase del Ebro del Plan Hidrol‚îú‚îÇgico Nacional, el domingo 8 de octubre de 2000, a su paso por la calle de Alfonso I. Al fondo, el Coso Alto. Fuente: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Arag‚îú‚îÇn", UGT, 2000.', 2000, 2000, 2000, 'Siglo XXI', 'CENTRO', 41.65441900, -0.88091300, '0101000020E610000043E1B3757030ECBFC5707500C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23641831323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23641831323.webp', 'https://www.flickr.com/photos/zaragozaantigua/23641831323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23110, 'Calle de Alfonso I 2006', 'S‚îú√≠bado 4 de noviembre de 2006. Manifestaci‚îú‚îÇn contra la OTAN en Zaragoza, "Por una cultura de la paz, hace 20 a‚îú‚ñíos y ahora", en alusi‚îú‚îÇn a las movilizaciones contra la Organizaci‚îú‚îÇn del Tratado del Atl‚îú√≠ntico Norte que se produjeron en 1986, a‚îú‚ñío del refer‚îú¬Ændum sobre la permanencia de Espa‚îú‚ñía. Esta vez, en contra de la instalaci‚îú‚îÇn de la sede del Sistema de Vigilancia A‚îú¬Ærea de Superficie (AGS) de la OTAN en suelo zaragozano. La oposici‚îú‚îÇn ciudadana, pese al apoyo del gobierno socialista aragon‚îú¬Æs, fue uno de los motivos por los que esta sede no acab‚îú‚îÇ en la ciudad, estando prevista su instalaci‚îú‚îÇn en Sicilia. En la foto, cabecera de la manifestacion, en el tramo de la calle de Alfonso I entre Cuatro de Agosto y la plaza de Sas. El domingo 21 de enero de 2007 hubo otra manifestaci‚îú‚îÇn con el mismo prop‚îú‚îÇsito. Fuente: Agencia EFE.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65388200, -0.88139600, '0101000020E61000002B685A626534ECBFB7B8C667B2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24772919305.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24772919305.webp', 'https://www.flickr.com/photos/zaragozaantigua/24772919305/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23118, 'Calle Jussepe Mart‚îú¬°nez 2006', 'Foto: Jos‚îú¬Æ Miguel Marco. Andamio colocado en los n‚îú‚ïëmeros 9 al 13 de la calle de Jussepe Mart‚îú¬°nez, que permaneci‚îú‚îÇ colocado all‚îú¬° durante once a‚îú‚ñíos, desde 1999 hasta 2010. Fuente: Heraldo de Arag‚îú‚îÇn.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65438500, -0.87987300, '0101000020E6100000E144F46BEB27ECBF19FF3EE3C2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31100003844.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31100003844.webp', 'https://www.flickr.com/photos/zaragozaantigua/31100003844/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23125, 'Calle de Fuenclara 2006', 'Foto: Jos‚îú¬Æ Miguel Marco. Aspecto de las obras de restauraci‚îú‚îÇn a lo largo de 2006 de la fachada y la cubierta del palacio de Fuenclara, en la calle hom‚îú‚îÇnima. La restauraci‚îú‚îÇn integral y apertura al p‚îú‚ïëblico estaban previstas para 2008. En 2017 no se hab‚îú¬°an producido. Fuente: Heraldo de Arag‚îú‚îÇn.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65412100, -0.88235200, '0101000020E610000018EDF1423A3CECBF3C50A73CBAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31180618813.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31180618813.webp', 'https://www.flickr.com/photos/zaragozaantigua/31180618813/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22802, 'Calle de Violante de Hungr‚îú¬°a 1976', 'Imagen capturada desde la altura del moderno inmueble del n‚î¨‚ïë 8 de la calle de Luis Bermejo, y centrada en el Pabell‚îú‚îÇn Municipal de Deportes durante su proceso de construcci‚îú‚îÇn en la parcela delimitada por las calles de Violante de Hungr‚îú¬°a, de los Condes de Arag‚îú‚îÇn, y la referida de Luis Bermejo. El poblado ferial del fondo, en el que destaca la carpa del Circo Atlas, indica la realizaci‚îú‚îÇn de esta toma durante las fiestas mayores de la ciudad, en octubre. Al fondo, la Escuela de Idiomas, dependencias traseras del Hospital Cl‚îú¬°nico Universitario, y Campus de la Universidad, con el solar donde luego se construir‚îú¬°a la nueva Facultad de Medicina, adem‚îú√≠s de la gran pista de equitaci‚îú‚îÇn de los terrenos de La H‚îú¬°pica.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63974100, -0.90397900, '0101000020E610000043AA285E65EDECBF86747808E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47942666627.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47942666627.webp', 'https://www.flickr.com/photos/zaragozaantigua/47942666627/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23214, 'Calle de Contamina 2017', 'Imagen capturada durante el derribo de tres antiguos inmuebles en la esquina de las calles de Contamina (el n‚î¨‚ïë 14, y el n‚î¨‚ïë 16), y la de Mat‚îú¬°as Carrica (el n‚î¨‚ïë 11-13). La imagen se centra en el esquinero n‚î¨‚ïë 16 de Contamina. Hacia la derecha se abre la antigua calle de Luna/de la Luna, desde 1942 redenominada Maestro Luna. El derribo de estos inmuebles, de propiedad municipal, fue aprobado tiempo ha al objeto de &quot;esponjar&quot; esta zona del Casco Antiguo de la ciudad y habilitar un solar como espacio de encuentro ciudadano a 70 m. de la plaza de San Felipe, 135 m. de la plaza del Justicia y 140 m. de la plaza de Sas. Los tres inmuebles, al no tener antecedentes de prestigio edilicio, o de fama positiva asociada a ellos, no estaban catalogados y fueron retirados del escenario urbano en el tr‚îú√≠nsito del a‚îú‚ñío 2016 al 2017. El participativo solar resultante cuenta con la protecci‚îú‚îÇn simb‚îú‚îÇlica de dos c‚îú‚îÇrvidos rupestres, bidimensionales y solitarios. Fuente visual: foto Jos‚îú¬Æ Mar‚îú¬°a Ballest‚îú¬°n Miguel', 2017, 2017, 2017, 'Siglo XXI', 'CENTRO', 41.65502700, -0.88118200, '0101000020E6100000295DFA97A432ECBF9D7FBBECD7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36570908822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36570908822.webp', 'https://www.flickr.com/photos/zaragozaantigua/36570908822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23221, 'Callej‚îú‚îÇn de Torres Secas 2019', 'Imagen promocional de la pel‚îú¬°cula "Las ni‚îú‚ñías" dirigida por Pilar Palomero y rodada en localizaciones de Zaragoza. En este caso, las ni‚îú‚ñías protagonistas de la cinta (de izquierda a derecha: "Clara", Ainara Nieto; "Leyre", Elisa Mart‚îú¬°nez; "Brisa", Zoe Arnao; "Cristina", Julia Sierra; "Vanessa", Carlota Gurpegui; y "Celia", Andrea Fandos) posan en la antigua calle de Torres Secas, convertida en callej‚îú‚îÇn desde que se cerr‚îú‚îÇ el ingreso desde el Coso Alto, y que recuerda a la desaparecida y hom‚îú‚îÇnima casa de los condes de Torres Secas. Al fondo, puerta azul que conserva en su parte superior la inscripci‚îú‚îÇn "Jos‚îú¬Æ Alfonso" por dar acceso trasero a este veterano establecimiento de drogas. A la izquierda y fuera de plano queda el palacio de Fuenclara, y a la derecha aparecen pegados a la pared, para dar la ambientaci‚îú‚îÇn requerida de principios de los pr‚îú‚îÇdigos a‚îú‚ñíos 90, cuando transcurre la trama de esta pel‚îú¬°cula, varios carteles de los exitosos y locales grupos de m‚îú‚ïësica popular del momento: H‚îú¬Æroes del Silencio (su LP de 1990, "Senderos de traici‚îú‚îÇn" y Ni‚îú‚ñíos del Brasil (su LP de 1993, "Mundos en eclipse").', 2019, 2019, 2019, 'Siglo XXI', 'CENTRO', 41.65402000, -0.88261800, '0101000020E6100000B98C9B1A683EECBF087767EDB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50843609408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50843609408.webp', 'https://www.flickr.com/photos/zaragozaantigua/50843609408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23225, 'Plaza San Felipe 2016', 'El 3 de diciembre de 2016 se inaugur‚îú‚îÇ en la plaza de San Felipe √î√á¬£El quiosco. Mapas de Poder en Zaragoza√î√á√ò, que permaneci‚îú‚îÇ all‚îú¬° durante dos semanas. Se trataba de un puesto callejero en el que se repart‚îú¬°an distintas publicaciones informativas respecto a la iniciativa √î√á¬£Qui‚îú¬Æn manda en Zaragoza√î√á√ò, puesta en marcha por el colectivo A Zofra. Esas publicaciones inclu‚îú¬°an estudios detallados sobre el verdadero poder local, con la colaboraci‚îú‚îÇn de 20 artistas pl‚îú√≠sticos, entre los que se encontraba Jos‚îú¬Æ Luis Cano. En la foto, vista del citado quiosco, con la calle de Antonio Candalija al fondo.', 2016, 2016, 2016, 'Siglo XXI', 'CENTRO', 41.65473300, -0.88202800, '0101000020E61000005000C5C89239ECBF554E7B4ACED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52461017984.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52461017984.webp', 'https://www.flickr.com/photos/zaragozaantigua/52461017984/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23777, 'Torre de Santa Engracia 1935', 'Imagen de la fachada del cuadrangular y recio edificio principal de la Torre de Santa Engracia, en el barrio de Movera, construida en el siglo XVII como propiedad del monasterio jer‚îú‚îÇnimo de Santa Engracia, y decorada con llamativos medallones. En el momento de realizar esta captura, posiblemente estaba siendo utilizado como casa de labor propiedad de la familia Casa‚îú‚ñía. Se accede a ella desde un antiguo camino vecinal, luego carretera, que une Movera con Pastriz, propiedad de la DPZ. Fuente visual: foto Juan Mora Insa, en AHPZ.', 1935, 1935, 1935, 'Anos 30', NULL, 41.64234700, -0.80543500, '0101000020E610000067B8019F1FC6E9BF84D72E6D38D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33289545192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33289545192.webp', 'https://www.flickr.com/photos/zaragozaantigua/33289545192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23277, 'Plaza de Sas 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/enero 1966. Imagen de la Plaza de Sas tomada desde la calle Antonio Candalija. Un poco antes de la calle Est‚îú¬Æbanes, captura del edificio que all‚îú¬° se levantaba a‚îú‚ïën en los a‚îú‚ñíos del desarrollismo franquista, con tienda de "Helados" y una "Oficina de viajes" haciendo esquina Blas‚îú‚îÇn Aragon‚îú¬Æs. Planta de palacete renacentista a la zaragozana (en ladrillo), bien majo, robusto, y con uno de esos aleros de madera tan superlativos. Con las modas del barroco, se puso a la moda est‚îú¬Ætica de la ‚îú¬Æpoca, con una espectacular decoraci‚îú‚îÇn de la puerta principal de ingreso, siendo ya la casona de los barones de La Linde, en la de toda la vida plaza del Carb‚îú‚îÇn. Llegados a finales de los sesenta del siglo pasado, este edificio ten‚îú¬°a una grave deficiencia: poco aprovechamiento vertical. Los propietarios actuaron para remediarlo, y el resultado salta a la vista hoy: ya no est‚îú√≠, sustituido por uno de esos horrores contempor‚îú√≠neos que plaguean el casco hist‚îú‚îÇrico de la ciudad. Casi todos los dem‚îú√≠s de la plaza, retocados en mayor o menor grado, perduran. Y los coches han volado.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65380300, -0.88069700, '0101000020E610000013EE9579AB2EECBF6B8313D1AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14664590659.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14664590659.webp', 'https://www.flickr.com/photos/zaragozaantigua/14664590659/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23280, 'Plaza de Sas 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/enero 1966. Imagen de la Plaza de Sas tomada desde la calle Antonio Candalija. Un poco antes de la calle Est‚îú¬Æbanes, al fondo a la derecha, captura del antiguo palacio de los barones de La Linde, con tienda de "Helados" y una "Oficina de viajes" haciendo esquina con la calle Blas‚îú‚îÇn Aragon‚îú¬Æs. Para mucha gente, lo m‚îú√≠s importante de esta imagen son los coches, los helados, y las veces que han pasado por esta antigua plaza del Carb‚îú‚îÇn.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65386700, -0.88071900, '0101000020E610000008E8BE9CD92EECBF8177F2E9B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14848098031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14848098031.webp', 'https://www.flickr.com/photos/zaragozaantigua/14848098031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23281, 'Plaza de Sas 1966', 'Imagen de la antigua plaza del Carb‚îú‚îÇn, luego redenominada de Sas, tomada desde la calle Alfonso I. A la derecha de la embocadura con la calle Est‚îú¬Æbanes, captura del edificio que albergaba al antiguo e irrepetible palacio de los barones de La Linde, entonces modernizado en sus bajos con una tienda de "Helados" y una "Oficina de viajes" en la esquina con la calle Blas‚îú‚îÇn Aragon‚îú¬Æs. Su escaso aprovechamiento vertical, y su mal gusto provinciano, muy reprochable para una ciudad tan cosmopolita como Zaragoza, fueron defectos radicalmente remediados a‚îú‚ñíos despu‚îú¬Æs: fue demolido, y sustituido por otra cosa. Los dem‚îú√≠s edificios de esta plaza, si bien retocados en mayor o menor grado, perduran. Fuente visual: Gerardo Sancho Ramo, Archivo P‚îú‚ïëblico Municipal.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65385100, -0.88080500, '0101000020E6100000ABE7A4F78D2FECBF7CBABA63B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871079983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871079983.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871079983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23283, 'Calle de Alfonso I c.1968', 'Calle de Alfonso I; microb‚îú‚ïës.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65368500, -0.88145900, '0101000020E6100000C4793881E934ECBF617138F3ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14894510046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14894510046.webp', 'https://www.flickr.com/photos/zaragozaantigua/14894510046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24356, 'Romareda 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 18/02/1974. El Pol‚îú¬°gono Romareda va tomando forma con una perspectiva estilo Brasilia. Imagen tomada desde As‚îú¬°n y Palacios, con la nueva Parroquia de Santa M‚îú‚îÇnica a la derecha.', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63729600, -0.90443500, '0101000020E6100000C5724BAB21F1ECBF91EF52EA92D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14948526402.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14948526402.webp', 'https://www.flickr.com/photos/zaragozaantigua/14948526402/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23286, 'Plaza de Sas 1965', 'Imagen de la antigua plaza del Carb‚îú‚îÇn, redenominada de Sas, capturada desde cierta altura de la calle Alfonso I, con la parafernalia de la "Cofrad‚îú¬°a de las Siete Palabras y de San Juan Evangelista." A la izquierda, esquinero con la calle del Pino (antigua continuaci‚îú‚îÇn de la calle de las V‚îú¬°rgenes), el n‚î¨‚ïë 4 de la plaza, obra de Jos‚îú¬Æ de Yarza en trazas modernistas de principios del siglo, para vivienda de Antonio Mar‚îú¬°a de Tro. Ocupado d‚îú¬Æcadas despu‚îú¬Æs por el femenino Liceo Hispano, fue convenientemente demolido a finales de los a‚îú‚ñíos 70, y sustituido por otra cosa. La actual. Fuente visual: Estudio Coyne (AHPZ-DARA).', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65380300, -0.88069700, '0101000020E610000013EE9579AB2EECBF6B8313D1AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15118110745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15118110745.webp', 'https://www.flickr.com/photos/zaragozaantigua/15118110745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23289, 'Colegio de las V‚îú¬°rgenes 1850', 'Litograf‚îú¬°a dibujada por J. B. Waring y publicada en Londres, 1850. Colegio de las V‚îú¬°rgenes con su caracter‚îú¬°stico torre‚îú‚îÇn, en la esquina de las calles V‚îú¬°rgenes (al fondo) y Torre Nueva (puerta de ingreso, a la derecha). La vista es desde la calle del Pino,', 1850, 1850, 1850, 'Siglo XIX', 'CENTRO', 41.65410000, -0.88014600, '0101000020E61000002191B6F1272AECBF24287E8CB9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19318235528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19318235528.webp', 'https://www.flickr.com/photos/zaragozaantigua/19318235528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23302, 'Calle de Alfonso I 1968', 'Sesentera imagen de una canicular tarde en la calle de Alfonso I, en la acera de los pares, manzana entre la calle Jussepe Mart‚îú¬°nez (antigua de Goya), y la de Casto M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez (al frente). Inmediata, la veterana y Art Dec‚îú‚îÇ "Librer‚îú¬°a y Papeler‚îú¬°a Aperte". Por la acera, desfile de lacas, cardados y vol‚îú‚ïëmenes locos en las se‚îú‚ñíoras a la moda del momento. Al fondo, el Coso Alto con la original sede del Banco de Arag‚îú‚îÇn, ya despejado de su ruidoso y recordado remate sireno. Fuente: "Zaragoza Viva" (1969).', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65446300, -0.88070700, '0101000020E6100000F7764B72C02EECBF95B88E71C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24245710180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24245710180.webp', 'https://www.flickr.com/photos/zaragozaantigua/24245710180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23781, 'Acampo de Funes 2009', 'Vista a‚îú¬Ærea del antiguo acampo de Funes, con el pol‚îú¬°gono industrial Empresarium de La Cartuja Baja a la izquierda, y el Parque Tecnol‚îú‚îÇgico de Reciclado L‚îú‚îÇpez Soriano a la derecha. Abajo, el Canal Imperial de Arag‚îú‚îÇn. Fuente: APUDEPA, en www.revistadepatrimonio.es', 2009, 2009, 2009, 'Siglo XXI', NULL, 41.59267100, -0.82689200, '0101000020E6100000785E2A36E675EABFD124B1A4DCCB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40078000131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40078000131.webp', 'https://www.flickr.com/photos/zaragozaantigua/40078000131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23304, 'Calle de Alfonso I 1964', 'Imagen del ya tradicional ese a‚îú‚ñío (como desde 1948) "paso de la tercera palabra", por la "cofrad‚îú¬°a de las siete palabras y de san Juan evangelista", el viernes 8 de abril de ese a‚îú‚ñío. La procesionaria se localiza en la calle de Alfonso I. A la izquierda, m‚îú√≠s que interesante captura del derribo de la antigua finca de los n‚îú‚ïëmeros 5-7-9 de la calle Fuenclara, y 17 de Alfonso I, que apenas contaba con un siglo de antig‚îú‚ïùedad, y que fue construida cuando la apertura de esta reciente calle. Sobre su amplio solar estaba proyectado el nuevo establecimiento de los familiares y grandes almacenes "GAY", especialistas de art‚îú¬°culos del hogar y moda, que se inaugurar‚îú¬°a el a‚îú‚ñío siguiente. Este edificio fue pionero en la tipolog‚îú¬°a vertical y opaca que los nuevos grandes centros comerciales de la ciudad seguir‚îú¬°an durante las siguientes d‚îú¬Æcadas. A la derecha, soleada, la plaza de Sas, antigua del Carb‚îú‚îÇn. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65372500, -0.88147900, '0101000020E61000008B8BA3721335ECBFEFC9C342ADD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26120855024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26120855024.webp', 'https://www.flickr.com/photos/zaragozaantigua/26120855024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23309, 'Plaza de Sas 1964', 'Imagen de la plaza de Sas, antigua del Carb‚îú‚îÇn, durante el paso de la Cofrad‚îú¬°a de las Siete Palabras y de San Juan Evangelista. La toma est‚îú√≠ centrada en el soleado tramo de los pares, donde destaca el edificio n‚î¨‚ïë 4, esquinero con la calle del Pino, obra de Jos‚îú¬Æ de Yarza en trazas modernistas de principios del siglo XX, ocupado por el femenino Liceo Hispano, y con interesantes bajos comerciales. A‚îú‚ñíos despu‚îú¬Æs fue demolido, y sustituido por un bloque de as‚îú¬Æptica e impersonal nueva planta moderna. Su vecino de la izquierda fue profundamente remodelado, aunque conserv‚îú‚îÇ la antigua traza de los balcones. Fuente visual: Estudio Coyne, AHPZ.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65392600, -0.88085700, '0101000020E61000004A7CEE04FB2FECBF8600E0D8B3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31511956432.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31511956432.webp', 'https://www.flickr.com/photos/zaragozaantigua/31511956432/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23441, 'Plaza de San Felipe 1951', '"Plaza de San Felipe [Calle Torre Nueva]." A la izquierda, el entronque de la plaza con la calle de Torre Nueva y lateral derecho del edificio del Torre‚îú‚îÇn Fortea. A la derecha, el retranqueado inmueble del n‚î¨‚ïë 31 (accesorio a los n‚îú‚ïëmeros 1-3 de la calle de Mat‚îú¬°as Carrica, antigua de la Luna), que posiblemente fuera la antigua casa de Jer‚îú‚îÇnimo Urrea, y que en el momento de realizar la fotograf‚îú¬°a era propiedad de los hijos de Pedro La‚îú¬°n como negocio de venta de cueros. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65471700, -0.88189900, '0101000020E6100000DA006C408438ECBF4F9143C4CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14897694220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14897694220.webp', 'https://www.flickr.com/photos/zaragozaantigua/14897694220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23442, 'Pl. de San Felipe 1967', 'Imagen centrada en la rotunda fachada del Torre‚îú‚îÇn Fortea, o antigua casa de los Cerd‚îú√≠n de Escatr‚îú‚îÇn, de f‚îú√≠brica bajomedieval con modificaciones en los siglos XV y XVI. Fuente visual: fotograf‚îú¬°a de Guillermo Fat‚îú√≠s Ojuel en Torralba, Federico; G‚îú‚îÇmez de Valenzuela, Manuel, Cat‚îú√≠logo de monumentos hist‚îú‚îÇricos-art‚îú¬°sticos y edificios de inter‚îú¬Æs para el estudio del arte en la ciudad de Zaragoza, Bolet‚îú¬°n municipal de Zaragoza, 1967.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65485300, -0.88200200, '0101000020E6100000003620425C39ECBF00581D39D2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938069891.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938069891.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938069891/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23457, 'Torre‚îú‚îÇn Fortea 1918', 'En el s. XV fue levantada la maciza torre de la casa de la familia Cerd‚îú√≠n de Escatr‚îú‚îÇn. En 1785 los bajos fueron ocupados por un comercio de pa‚îú‚ñíos y telas de Joaqu‚îú¬°n Fortea, quedando el apellido asociado comercialmente al edificio. En 1981 el edificio fue adquirido por el Ayuntamiento. En la imagen, vista del torre‚îú‚îÇn "de Fortea" capturada junto a la iglesia de San Felipe, la sombra de cuya torre se proyecta en la plaza. La planta baja, ocupada por el local comercial de "Jos‚îú¬Æ Monta‚îú‚ñí‚îú¬Æs y Compa‚îú‚ñí‚îú¬°a". A la izquierda, la calle del Temple. A la derecha del torre‚îú‚îÇn, el edificio de viviendas levantado junto a ‚îú¬Æl, aunque independiente. La Torre Nueva se levantaba donde el quiosco de la imagen. Pocos a‚îú‚ñíos despu‚îú¬Æs ser‚îú√≠ sustituido por un mingitorio. Fuente: Instituto Amatller de Arte Hisp‚îú√≠nico (Arxiu Mas).', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15734548360.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15734548360.webp', 'https://www.flickr.com/photos/zaragozaantigua/15734548360/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23461, 'Torre‚îú‚îÇn Fortea 1985', 'La Antigua Casa Fortea, con su torre‚îú‚îÇn g‚îú‚îÇtico-mud‚îú¬Æjar del siglo XV, sita en la plaza de San Felipe de Zaragoza, es un palacio del siglo XVI que fue rehabilitado para albergar el ‚îú√≠rea de Cultura del Ayuntamiento de Zaragoza desde 1991. En 1985 presentaba este aspecto, sensiblemente distinto al actual. Fuente visual: Fotograma del audiovisual "El ‚îú‚ïëltimo nombre. Miguel Labordeta" (Emilio Alfaro, 1985).', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20959878299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20959878299.webp', 'https://www.flickr.com/photos/zaragozaantigua/20959878299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23464, 'Plaza San Felipe 1967', 'Vista del torre‚îú‚îÇn de Fortea en la plaza de San Felipe. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23133296342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23133296342.webp', 'https://www.flickr.com/photos/zaragozaantigua/23133296342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23474, 'Plaza de San Felipe 1910', 'Placa autocroma de una vista de la plaza de San Felipe con el fondo esc‚îú¬Ænico de la antigua casa de los Cerd‚îú√≠n de Escatr‚îú‚îÇn, caracter‚îú¬°sticamente esquinera con la calle del Temple (a la izquierda) mediante su enorme torre‚îú‚îÇn. Fuente visual: Charles Jacquin photographe bibliotheques-specialisees.paris.fr/', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.65477800, -0.88209400, '0101000020E61000002DEE3F321D3AECBFF511F8C3CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32133475674.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32133475674.webp', 'https://www.flickr.com/photos/zaragozaantigua/32133475674/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23480, 'Pl. de San Felipe 1985', 'Imagen capturada durante las obras de restauraci‚îú‚îÇn y reconversi‚îú‚îÇn de la antigua casa de los Cerd‚îú√≠n de Escatr‚îú‚îÇn (luego de los Fortea) al objeto de albergar las dependencias municipales del ‚îú√ºrea de Cultura. La fotograf‚îú¬°a se ha realizado desde la zona del patio interior. A la derecha, dando fachada principal a la inmediata plaza de San Felipe, traseras del Torre‚îú‚îÇn de Fortea y la Casa Montal. Al fondo, el moderno bloque edilicio del n‚î¨‚ïë 31 de la calle Torrenueva. Fuente visual: AMZ.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.65492800, -0.88180100, '0101000020E6100000259012BBB637ECBF0A9E42AED4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39106316095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39106316095.webp', 'https://www.flickr.com/photos/zaragozaantigua/39106316095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23487, 'Calle de la Torre Nueva 1951', 'Imagen del tramo de la calle de la Torre Nueva inmediatamente posterior a la plaza de San Felipe, centrado en el soleado tramo de los n‚îú‚ïëmeros impares, donde destaca el edificio del Torre‚îú‚îÇn Fortea, el negocio de alimentaci‚îú‚îÇn regentado por Juli‚îú√≠n y Benigno Montal, y en primer t‚îú¬Ærmino el dieciochesco cerramiento de ingreso al patio del inmueble del n‚î¨‚ïë 31 (accesorio a los n‚îú‚ïëmeros 1-3 de la calle de Mat‚îú¬°as Carrica, antigua de la Luna), que posiblemente fuera la antigua casa de Jer‚îú‚îÇnimo Urrea, y que en el momento de realizar la fotograf‚îú¬°a era propiedad de los hijos de Pedro La‚îú¬°n y regentado como negocio de venta de cueros.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65446100, -0.88172700, '0101000020E61000009301A08A1B37ECBFF4C0C760C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47954299601.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47954299601.webp', 'https://www.flickr.com/photos/zaragozaantigua/47954299601/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23493, 'Plaza de San Felipe c.1908', 'Imagen capturada en la plaza de San Felipe y centrada en la imponente presencia de la antigua casa del siglo XV de los Cerd‚îú√≠n de Escatr‚îú‚îÇn y que desde el siglo XVIII es denominada de Fortea. A la izquierda, la calle del Temple y el inmueble esquinero del reputado comercio textil "N‚îú‚ïëmero 1". A la derecha , vista parcial del inmueble del n‚î¨‚ïë 37 de la calle de Torrenueva, correspondiente al Almac‚îú¬Æn de Frutos Coloniales Hijo de Navarro P‚îú¬Ærez, que a‚îú‚ñíos despu‚îú¬Æs continuar‚îú¬°a bajo la familia Montal.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65486900, -0.88201700, '0101000020E6100000568330B77B39ECBF051555BFD2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51646815407.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51646815407.webp', 'https://www.flickr.com/photos/zaragozaantigua/51646815407/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23523, 'Calle Galo Ponte 2011', 'Foto: Oliver Duch. Vista, desde la esquina de las calles de Galo Ponte (izquierda) y Morata, del estado en agosto de 2011 de las obras de construcci‚îú‚îÇn de la nueva sede de la Audiencia Provincial de Zaragoza, inaugurada en 2012. Al fondo a la izquierda, el Coso Alto, con el palacio de los Condes de Morata o de los Luna, que quedar‚îú√≠ como Tribunal Superior de Justicia de Arag‚îú‚îÇn. Las plantas de este nuevo edificio se levantan coincidentes con las de su anexo precedente, el de la Imprenta Blasco, que asoma a la derecha, "por si en un futuro hay que unirlos". Fuente: Heraldo de Arag‚îú‚îÇn.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.65452200, -0.88269300, '0101000020E6100000620FED63053FECBF9A417C60C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38242611492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38242611492.webp', 'https://www.flickr.com/photos/zaragozaantigua/38242611492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23662, 'Plaza de San Felipe 1937', 'Imagen de la plaza de San Felipe con detalle de la fachada de la antigua casa del marqu‚îú¬Æs de Villaverde. El "colegio de San Felipe", all‚îú¬° ubicado desde 1860, tras el golpe de estado de julio de 1936 se convirti‚îú‚îÇ en otro de los espacios militarizados por los sublevados nacionalistas en Zaragoza, en un primer momento como sede del Sector n‚î¨‚ïë 1 de la organizaci‚îú‚îÇn paramilitar "Acci‚îú‚îÇn Ciudadana". La fotograf‚îú¬°a ha sido realizada despu‚îú¬Æs del decreto n‚î¨‚ïë 255 (promulgado en Salamanca en abril de ese a‚îú‚ñío), de unificaci‚îú‚îÇn de todas las fuerzas derechistas en un partido ‚îú‚ïënico, siguiendo el modelo de los fascistas italianos y alemanes. Desde ese momento este colegio fue reconvertido como cuartel del "Primer Sector" de la milicia nacional de FET de las JONS, el nuevo partido surgido de la unificaci‚îú‚îÇn de Falange, requet‚îú¬Æs, Acci‚îú‚îÇn Ciudadana, Renovaci‚îú‚îÇn Espa‚îú‚ñíola, Acci‚îú‚îÇn Popular, et altera. Aqu‚îú¬° tambi‚îú¬Æn la divisa era "todo por la patria", y la bandera mon‚îú√≠rquica tapa el veterano cartel del colegio. Poco despu‚îú¬Æs de tomar esta imagen, otro decreto estableci‚îú‚îÇ que todos los concejales y diputados provinciales ten‚îú¬°an que ser numerarios del partido. La replaceta junto a la antigua casona ten‚îú¬°a buena solanera para ponerse en posici‚îú‚îÇn de espalda al sol.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65477200, -0.88213600, '0101000020E6100000E8F9D346753AECBF132BA391CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25633742253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25633742253.webp', 'https://www.flickr.com/photos/zaragozaantigua/25633742253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23995, 'Zaragoza 1591', '"Entran en Zaragoza las tropas castellanas", dibujo del siglo XIX, rom‚îú√≠ntico y ahist‚îú‚îÇrico, recreando de esas formas la entrada del ej‚îú¬Ærcito castellano en la ciudad durante las alteraciones del verano de 1591. Al fondo, la Torre Nueva, sorprendentemente precoz: est‚îú√≠ provista de su barroco juego de chapiteles. Fuente: www.artres.com/', 1591, 1591, 1591, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20714785970.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20714785970.webp', 'https://www.flickr.com/photos/zaragozaantigua/20714785970/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24010, 'Calle de Alfonso I 1986', 'Foto: Arturo Burgos. Comitiva f‚îú‚ïënebre en el entierro del alcalde de Zaragoza Ram‚îú‚îÇn Sainz de Varanda, a su paso por la calle de Alfonso I, el 11 de enero de 1986 Fuente: Heraldo de Arag‚îú‚îÇn.', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.65374600, -0.88154600, '0101000020E61000007F6DFDF49F35ECBF06F2ECF2ADD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23997397634.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23997397634.webp', 'https://www.flickr.com/photos/zaragozaantigua/23997397634/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24059, 'Calle de Alfonso I 1931', 'Celebraciones de la llegada de la Segunda Rep‚îú‚ïëblica, el 14 de abril de 1931. En el centro, grupo de soldados que hab‚îú¬°an formado parte de la columna del capit‚îú√≠n Gal‚îú√≠n, en la sublevaci‚îú‚îÇn republicana de Jaca del 12 de diciembre de 1930. A la derecha, Joyer‚îú¬°a de Miguel Faci, en la esquina de la calle de Alfonso I con la plaza de Sas. Fuente visual: Heraldo de Arag‚îú‚îÇn.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65416100, -0.88102100, '0101000020E6100000DCDAC2F35231ECBFCAA8328CBBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31747330095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31747330095.webp', 'https://www.flickr.com/photos/zaragozaantigua/31747330095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24252, 'Calle de Alfonso I, c.1955', 'Luminosa imagen de la calle de Alfonso I donde destaca, a la derecha, el cartel‚îú‚îÇn publicitario del prestigioso Estudio Coyne en el inmueble del n‚î¨‚ïë 12, entresuelo. A la izquierda, el antiguo inmueble del n‚î¨‚ïë 17 esquinero con los n‚îú‚ïëmeros 5, 7 y 9 de la calle de Fuenclara. Al fondo, el templo del Pilar.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65383500, -0.88134100, '0101000020E610000049F7730AF233ECBF76FD82DDB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50129003428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50129003428.webp', 'https://www.flickr.com/photos/zaragozaantigua/50129003428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24476, 'La Bola Dorada 1910', 'Bazar La Bola Dorada de Joaqu‚îú¬°n Grasa, en el n‚îú‚ïëmero 8 de la plaza de San Felipe, en su confluencia con la calle Montera (hoy Candalija 9). El fot‚îú‚îÇgrafo era hijo del propietario y hermano del ni‚îú‚ñío asomado al balc‚îú‚îÇn, Emilio, que se har‚îú¬°a cargo a‚îú‚ñíos despu‚îú¬Æs del negocio. Fuente: "Aurelio Grasa 1893-1972", Galer‚îú¬°a Costa, 3, 1976. P‚îú√≠gina 10. Form‚îú‚îÇ parte de la exposici‚îú‚îÇn conmemorativa celebrada en dicha galer‚îú¬°a en 1978. www.aureliograsa.es', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.65454000, -0.88191100, '0101000020E6100000EB71DF6A9D38ECBF40F67AF7C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21223699900.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21223699900.webp', 'https://www.flickr.com/photos/zaragozaantigua/21223699900/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24521, 'Chocolate Francisco Navarro 1890', 'Imagen publicitaria de 1890 de la "f‚îú√≠brica de chocolate elaborado a brazo" de Francisco Navarro, con direcci‚îú‚îÇn en la calle Torre Nueva 37. Representa la Torre Nueva antes de ser desmochada, con la casa de la familia Cerd‚îú√≠n de Escatr‚îú‚îÇn (Torre‚îú‚îÇn Fortea) a su izquierda. Fuente: Oficina Espa‚îú‚ñíola de Patentes y Marcas.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65472200, -0.88213500, '0101000020E6100000D105F52D733AECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39292070314.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39292070314.webp', 'https://www.flickr.com/photos/zaragozaantigua/39292070314/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25146, 'Torre Nueva 1813', 'Imagen de la Torre Nueva dibujada por Edward Hanke Locker en 1813, convertida en la "Torre de San Felipe" en la edici‚îú‚îÇn de 1824 de "Views in Spain", por John Murray. Si interpretamos bien la ilustraci‚îú‚îÇn, la torre de la iglesia de San Felipe que aparece representada ser‚îú¬°a el desproporcionado torre‚îú‚îÇn de la izquierda, mientras que la Torre Nueva ser‚îú¬°a, empeque‚îú‚ñíecida respecto a su real tama‚îú‚ñío, la de la derecha. Al fondo, el palacio de los marqueses de Villaverde. Por la plaza de San Felipe circula una procesionaria. Fuente visual: www.ebay.es/', 1813, 1813, 1813, 'Siglo XIX', 'CENTRO', 41.65477200, -0.88213600, '0101000020E6100000E8F9D346753AECBF132BA391CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26502678592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26502678592.webp', 'https://www.flickr.com/photos/zaragozaantigua/26502678592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25183, 'Torre Nueva 1865', 'Curioso dibujo de la Torre Nueva en la plaza de San Felipe que parece intentar reflejar un h‚îú¬°brido entre el estado original de la torre al que se le suma el caracter‚îú¬°stico remate barroco en chapitel, que aqu‚îú¬° aparece achatado de forma extra‚îú‚ñía. Al fondo y a la izquierda, en trazo m‚îú√≠s tenue, la casa de los condes de Argillo y marqueses de Villaverde, y el muro de cerramiento de la iglesia de San Felipe.', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.65476500, -0.88210300, '0101000020E6100000F9821612303AECBF60C8EA56CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50902804946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50902804946.webp', 'https://www.flickr.com/photos/zaragozaantigua/50902804946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25667, 'M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez 1966', 'Imagen de la calle M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez a la altura, a la derecha, de la antigua plazuela de la Cabra, interesante espacio urbano con restos de casonas de notable prestigio urbano. A la izquierda, aspecto de la calle cuando en los bajos del n‚î¨‚ïë 16 (a los que se a‚îú‚ñíad‚îú¬°a el 18 de la vecina calle Libertad) estaba radicado el establecimiento comercial de la veterana empresa "Muebles y Camas Met‚îú√≠licas Viuda de S. Irisarri", cuya f‚îú√≠brica estaba en el Barrio del Castillo. Al fondo, M‚îú¬Ændez N‚îú‚ïë‚îú‚ñíez asciende desde su arranque en Alfonso I. Fuente: Gerardo Sancho Ramo (Archivo P‚îú‚ïëblico Municipal).', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65378100, -0.87976300, '0101000020E61000001B6327BC0427ECBF83DF8618AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24049716615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24049716615.webp', 'https://www.flickr.com/photos/zaragozaantigua/24049716615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25872, 'La Torre Nueva 1835', 'Grabado de la Torre Nueva realizado por Charles Heath en Londores (1835), basado fielmente en el can‚îú‚îÇnico dibujo previo de Edward Hanke Locker en 1813. Fuente visual: Fondo Documental Hist‚îú‚îÇrico de las Cortes de Arag‚îú‚îÇn', 1835, 1835, 1835, 'Siglo XIX', 'CENTRO', 41.65474400, -0.88209200, '0101000020E6100000FF058200193AECBF49A0C1A6CED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688169238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688169238.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688169238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25873, 'The Leaning Tower 1837', 'Fondo Documental Hist‚îú‚îÇrico de las Cortes de Arag‚îú‚îÇn. Ernest Georges (ca. 1837). The Leaning Tower, Saragosse. (La Torre Nueva).', 1837, 1837, 1837, 'Siglo XIX', 'CENTRO', 41.65469300, -0.88218300, '0101000020E610000015CAC2D7D73AECBFC7F5EFFACCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14874540941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14874540941.webp', 'https://www.flickr.com/photos/zaragozaantigua/14874540941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25874, 'Der Haengende Thurm 1837', 'Der Haengende Thurm in Saragossa. Johann Gabriel Friedrich Poppel, (ca. 1850). Reproducci‚îú‚îÇn del grabado de E. Finden seg‚îú‚ïën un dibujo de J. F. Lewis de 1837. Fuente: Arag‚îú‚îÇn en el mundo. CAI, 1988.', 1837, 1837, 1837, 'Siglo XIX', 'CENTRO', 41.65474600, -0.88208600, '0101000020E6100000774D486B0C3AECBFEA9788B7CED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877300682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877300682.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877300682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25876, 'Torre Nueva 1844', '"Torre inclinada (Zaragoza)". A la derecha, el Palacio de los Cerd‚îú√≠n de Escatr‚îú‚îÇn. Al fondo, el Palacio de Argillo; a la izquierda, la iglesia de San Felipe. Fuente visual: "Recuerdos y Bellezas de Espa‚îú‚ñía. Obra destinada a dar a conocer sus monumentos, antig‚îú‚ïùedades y vistas pintorescas en l‚îú√≠minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompa‚îú‚ñíadas de texto por P. Piferrer y J. M. Quadrado. Arag‚îú‚îÇn: Jos‚îú¬Æ Mar‚îú¬°a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19477637546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19477637546.webp', 'https://www.flickr.com/photos/zaragozaantigua/19477637546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25877, 'Plaza San Felipe 1980', 'Plaza de San Felipe, con tr‚îú√≠fico en la calle Torre Nueva. Al fondo, palacio de Argillo. Fuente: Zaragoza en im‚îú√≠genes, CAZAR, 1980.', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19638347474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19638347474.webp', 'https://www.flickr.com/photos/zaragozaantigua/19638347474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25880, 'Torre Nueva c.1863', 'Primera de las im‚îú√≠genes en altura desde la calle Torre Nueva, capturadas por Laurent y C‚îú¬°a, retratando la Torre Nueva en la plaza de San Felipe. Fuente visual: Jean Laurent y C‚îú¬°a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Hist‚îú‚îÇrico, www.mcu.es/)', 1863, 1863, 1863, 'Siglo XIX', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22412575193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22412575193.webp', 'https://www.flickr.com/photos/zaragozaantigua/22412575193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25881, '&quot;Torre Nueva&quot; 1976', 'Imagen de la Torre Nueva en la epifan‚îú¬°a discogr‚îú√≠fica del grupo musical "La Bullonera". La atinada composici‚îú‚îÇn visual aprovecha una fotograf‚îú¬°a de J. Laurent de este icono de la Zaragoza demolida por sus propios, para confrontar dos antag‚îú‚îÇnicas ciudades: la de la derecha, azulona, selecta, emprendedora, a color; la de la izquierda, roja, basal, colectiva, en tonos grises, que pugna por sostener la torre, porque es de todos. Esta realidad bipolar, reconocible e identitaria, luego confluy‚îú‚îÇ en amable mezcolanza de churros y merinos, dando como resultado el ahora en el que estamos. Fuente visual: disco en vinilo "La Bullonera" (Javier Maestre, Eduardo Paz), Madrid, Movieplay, 1976. Ilustraci‚îú‚îÇn y dise‚îú‚ñío de la carpeta por Jos‚îú¬Æ Luis Lasala, en colaboraci‚îú‚îÇn con Natalio Bayo.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23043877271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23043877271.webp', 'https://www.flickr.com/photos/zaragozaantigua/23043877271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25882, 'Calle Torre Nueva 1971', 'Calle Torre Nueva. Al fondo, plaza de San Felipe. M‚îú√≠s all‚îú√≠, la calle contin‚îú‚ïëa hasta el Mercado Central. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65470000, -0.88162100, '0101000020E610000028F04E3E3D36ECBF7958A835CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23133619532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23133619532.webp', 'https://www.flickr.com/photos/zaragozaantigua/23133619532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25883, 'Plaza de San Felipe c.1972', 'Tramo de la calle de la Torre Nueva que atraviesa la plaza de San Felipe. A la derecha, establecimientos comerciales de bebidas espirituosas y de g‚îú¬Æneros de punto en los bajos del Torre‚îú‚îÇn y casa-palacio Fortea, antigua vivienda de los Cerd‚îú√≠n de Escatr‚îú‚îÇn. En la d‚îú¬Æcada siguiente, este conjunto ser‚îú√≠ adquirido y restaurado por el Ayuntamiento, y luego adaptado a usos municipales, desahogando parcialmente el entorno de veh‚îú¬°culos a motor aparcados.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23177708125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23177708125.webp', 'https://www.flickr.com/photos/zaragozaantigua/23177708125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25884, 'Plaza de San Felipe 1968', 'Imagen del decorativo pozo en peculiar estilo neo-rom‚îú√≠nico ubicado en la plaza de San Felipe, muy cerca de donde estuviera la Torre Nueva. Al fondo, a la izquierda, la plazuela de ingreso al colegio de San Felipe. A la derecha, plazuela de engarce con las calles Torre Nueva, y Temple. Posteriores intervenciones en la plaza derivaron al pozo en situaci‚îú‚îÇn de paradero desconocido. Fuente visual: Walter Schr‚îú√Çder (www.bildindex.de/)', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23205559710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23205559710.webp', 'https://www.flickr.com/photos/zaragozaantigua/23205559710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25886, 'Torre Nueva c.1843', '"The leaning tower of Zaragoza". Este grabado fue publicado en el "Illustrated home book of the world''s great nations. Being a geographical, historical and pictorial encyclopedia", en Chicago, 1893. Estaba incluido en el cap‚îú¬°tulo dedicado al "romantic land of Spain", un folcl‚îú‚îÇrico recorrido por todos los t‚îú‚îÇpicos imaginables a este lado de los Pirineos, con el valor a‚îú‚ñíadido de una distorsionada mirada desde el pujante norte del otro lado del Atl‚îú√≠ntico. Se trataba, adem‚îú√≠s, de la ‚îú‚ïënica ilustraci‚îú‚îÇn de Zaragoza incluida en esa obra cuando, casualmente, desde un a‚îú‚ñío antes de su edici‚îú‚îÇn esta inmortal ciudad ya no contaba, por derribo promovido, con la Torre Nueva. El tardobarroco triple chapitel que la remataba, ya no estaba desde 1878. El grabado, cuyo "eminente artista" autor no es nominado, sigue bebiendo del can‚îú‚îÇnico dibujo de la Torre Nueva realizado por Edward Hanke Locker en 1813, con algunas modificaciones. Posiblemente, el tumulto que se desarrolla en la plaza de San Felipe estuviera relacionado con la resistencia a los pronunciamientos militares (as‚îú¬° se llamaban a los golpes de estado durante el siglo XIX) de 1843, durante la regencia del general Espartero. A la izquierda, la torre de la iglesia de San Felipe; al fondo, la galer‚îú¬°a de arquillos del palacio de los marqueses de Villaverde; en el centro de la acci‚îú‚îÇn, la "Torre inclinada de Zaragoza".', 1843, 1843, 1843, 'Siglo XIX', 'CENTRO', 41.65477200, -0.88213600, '0101000020E6100000E8F9D346753AECBF132BA391CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26570720156.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26570720156.webp', 'https://www.flickr.com/photos/zaragozaantigua/26570720156/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25887, 'Torre Nueva 1864', 'Vista de la Torre Nueva. Fuente: Mariano J‚îú‚ïëdez y Ortiz. Colecci‚îú‚îÇn Boisset-Ib‚îú√≠‚îú‚ñíez. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza.', 1864, 1864, 1864, 'Siglo XIX', 'CENTRO', 41.65477200, -0.88213600, '0101000020E6100000E8F9D346753AECBF132BA391CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28490644371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28490644371.webp', 'https://www.flickr.com/photos/zaragozaantigua/28490644371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25888, 'Pl. de San Felipe 1968', 'Imagen del patio al aire (y sol) de la antigua casa del infanz‚îú‚îÇn Francisco Sanz de Cort‚îú¬Æs, luego marqu‚îú¬Æs de Villaverde, sita en la plaza de San Felipe, inmediata a la iglesia parroquial. En el siglo XIX pas‚îú‚îÇ a manos de la condesa de Argillo, y acogi‚îú‚îÇ al Colegio de San Felipe. En el siglo XX fue una de las sedes de la paramilitar Acci‚îú‚îÇn Ciudadana, y luego lo fue de la ONCE. Desde 1977 es propiedad municipal, como museo. Fuente visual: Walter Schr‚îú√Çder, en www.bildindex.de/', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65475900, -0.88245600, '0101000020E61000005516855D143DECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32370057505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32370057505.webp', 'https://www.flickr.com/photos/zaragozaantigua/32370057505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25889, 'Plaza de San Felipe 1977', 'Imagen parcial de la renovada plaza de San Felipe, tras una de las operaciones entonces denominadas "de embellecimiento" de espacios de la vieja ciudad, que incluy‚îú‚îÇ esta est‚îú¬Ætica valla ornamental sin utilidad pr‚îú√≠ctica conocida, tal vez como recuerdo de la "valla mental" que supon‚îú¬°a la antigua Torre Nueva (ubicada en ese mismo lugar) para los vecinos que exigieron su aplaudida demolici‚îú‚îÇn. Parece ser que el concepto "plaza dura" ya se estaba imponiendo como pr‚îú√≠ctica habitual en el tratamiento de los espacios comunitarios de nueva ola. Al fondo de la imagen, almacenes de tejidos instalados en los bajos comerciales de la antigua casa de los Cerd‚îú√≠n de Escatr‚îú‚îÇn. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65477800, -0.88209400, '0101000020E61000002DEE3F321D3AECBFF511F8C3CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33244671871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33244671871.webp', 'https://www.flickr.com/photos/zaragozaantigua/33244671871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25890, 'Calle de Gil Berges 1972', 'Imagen centrada en el n‚î¨‚ïë 1 (antiguo n‚î¨‚ïë 5) de la calle de Gil Berges, en cuyos bajos estaba radicado el local de la veterana churrer‚îú¬°a "Bola de Plata", en un antiguo edificio posiblemente del siglo XVI que fue finalmente derribado a finales de los a‚îú‚ñíos noventa de la pasada centuria. A la izquierda, fuera de plano, la calle de Agustines. Hacia la derecha se accede a la iglesia parroquial de San Felipe, y a la plaza hom‚îú‚îÇnima. Este era considerado un "rinc‚îú‚îÇn t‚îú¬°pico" zaragozano, pintoresco, costumbrista, y contingente, que ya entonces se auguraba sentenciado a desaparecer por el impacto de una modernidad que parece ser que no hallaba otra forma de encontrar acomodo en zonas como esta, que no fuera con la piqueta por delante. Tambi‚îú¬Æn parece que era necesario, pese a lo recoleto de la zona, recordar a los conductores que el estacionamiento no estaba recomendado. Fuente visual: fotograf‚îú¬°a de Luis Mompel, en Heraldo de Arag‚îú‚îÇn.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65427800, -0.88256300, '0101000020E6100000D61BB5C2F43DECBF033FAA61BFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34366060633.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34366060633.webp', 'https://www.flickr.com/photos/zaragozaantigua/34366060633/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25891, 'Calle Torre Nueva c.1969', 'Imagen capturada en la calle de Torre Nueva y centrada en la esquinera fachada del n‚î¨‚ïë 29, correspondiente con el veterano negocio de alimentaci‚îú‚îÇn all‚îú¬° ubicado desde 1890 que desde 1919 es reconocido como Casa Montal. Hacia la izquierda, fuera de plano, la antigua casa de los Cerd‚îú√≠n de Escatr‚îú‚îÇn (luego de los Fortea). Fuente visual: www.montal.es', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65478300, -0.88171600, '0101000020E610000099840B790437ECBF077DE9EDCFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39978706102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39978706102.webp', 'https://www.flickr.com/photos/zaragozaantigua/39978706102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25892, 'Ejecuci‚îú‚îÇn nobles 1591', '"Ejecuci‚îú‚îÇn de los nobles don Diego de Heredia y don Juan de Luna en Zaragoza". Ilustraci‚îú‚îÇn de F. Blanch que recrea el pase‚îú¬°llo previo a la ejecuci‚îú‚îÇn de los nobles citados, que junto a Pedro Fuertes, Francisco de Ayerbe y otros fueron condenados a muerte por participar en las alteraciones de Zaragoza de 1591. Tras ellos fue ejecutado tambi‚îú¬Æn el Justicia Juan de Lanuza. La comitiva viene de la Torre Nueva y se dirige a la picota de la plaza del Mercado. Fuente visual: Historia de Espa‚îú‚ñía, Miguel Segu‚îú¬°, 1910, en todocoleccion.net.', 1591, 1591, 1591, 'Siglo XIX', 'CENTRO', 41.65511500, -0.88256400, '0101000020E6100000ED0F94DBF63DECBF3D0FEECEDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40390073704.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40390073704.webp', 'https://www.flickr.com/photos/zaragozaantigua/40390073704/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25893, 'Calle de Fuenclara c.1973', 'Imagen centrada en la fachada de la renacentista y enorme casa de los condes de Fuenclara, sita en la hom‚îú‚îÇnima calle y esquinera con las calles del Desenga‚îú‚ñío y de Torresecas. Adem‚îú√≠s de los seis locales comerciales ubicados en sus bajos, en ‚îú¬Æl se exhib‚îú¬°an pel‚îú¬°culas en la sala del cine Arlequ‚îú¬°n. Al fondo, el inmueble esquinero entre las calles de Agustines y de Gil Berges. Fuente visual: AMZ.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65401400, -0.88212300, '0101000020E6100000C09481035A3AECBF259012BBB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41036439775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41036439775.webp', 'https://www.flickr.com/photos/zaragozaantigua/41036439775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25894, 'Calle del Temple 1974', 'Imagen centrada en el destacable ingreso al antiguo n‚î¨‚ïë 15 de la calle del Temple, inmueble esquinero con la calle del Olmo. A‚îú‚ñíos m‚îú√≠s tarde, tanto este como el inmediato n‚î¨‚ïë 13, adem‚îú√≠s del n‚î¨‚ïë 11, que ya era solar, fueron habilitados como un provisional espacio de encuentro, convivencia y solaz ciudadano en el que este antiguo portal de ingreso fue el ‚îú‚ïënico resto edilicio que se mantuvo en pie. A principios del siglo XXI sobre este solar se emprendi‚îú‚îÇ un desarrollo constructivo que conform‚îú‚îÇ el actual gran inmueble del n‚î¨‚ïë 18 de la calle del Olmo. Esta vieja portada fue entonces derribada. Fuente visual: AMZ.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65551300, -0.88201600, '0101000020E61000003F8F519E7939ECBF2A8D98D9E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42267438434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42267438434.webp', 'https://www.flickr.com/photos/zaragozaantigua/42267438434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26025, 'Tejados 1899', 'A finales de la diecinueve centuria de la Era, desde las alturas del antiguo palacio de Guara, en la calle de la Montera, un vistazo en direcci‚îú‚îÇn norte choca con el frontal, al fondo, de la bas‚îú¬°lica del Pilar recayente a la plaza del mismo nombre. Justo enfrente, emerge solitaria la reciente torre de Santiago, acabada unos pocos a‚îú‚ñíos antes, y la imagen se corta a la derecha justo donde comienza el secular arranque que unos pocos a‚îú‚ñíos despu‚îú¬Æs, terminado ya en forma de torre, ser‚îú√≠ denominada "Nuestra Se‚îú‚ñíora del Pilar" para redundar el culto mariano en s‚îú¬° mismo. En medio, el caracter‚îú¬°stico mundo de los tejados, solanares y remates edilicios frontero entre el antiguo barrio de San Felipe, y el del Pilar. Fuente visual: Francisco G‚îú‚îÇrriz, Archivo Municipal de Zaragoza', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65440400, -0.88154500, '0101000020E610000068791EDC9D35ECBF902FA182C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28722003590.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28722003590.webp', 'https://www.flickr.com/photos/zaragozaantigua/28722003590/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21272, 'Cl‚îú¬°nica Dr. Lozano 1905', 'Imagen de la original f‚îú√≠brica de la particular cl‚îú¬°nica-palacete del m‚îú¬Ædico y cirujano Ricardo Lozano Monz‚îú‚îÇn, estrat‚îú¬Ægicamente situada entre el paseo de Sagasta y la calle Lagasca, con dise‚îú‚ñío de F‚îú¬Ælix Navarro. En 1916 ser‚îú√≠ ampliada y bastante modificada, a cargo de Manuel del Busto. Esto era lo que se ve‚îú¬°a antes de, desde la esquina con Lagasca. Fuente visual: "Zaragoza. Arquitectura siglo XX" (Jes‚îú‚ïës Mart‚îú¬°nez Ver‚îú‚îÇn).', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64496900, -0.88607300, '0101000020E6100000A3CB9BC3B55AECBF88F71C588ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22508018031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22508018031.webp', 'https://www.flickr.com/photos/zaragozaantigua/22508018031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21351, 'Paseo de Sagasta 1905', 'Imagen capturada en el arranque del paseo de Sagasta, donde a la izquierda queda el tramo comprendido entre el Vel‚îú‚îÇdromo y la calle de Mariano Lagasca, y a la derecha el tramo recayente al colegio del Sagrado Coraz‚îú‚îÇn o de "las francesas". Por el centro del bulevar transita su recorrido en ascenso hasta la playa de Torrero el el‚îú¬Æctrico coche n‚îú‚ïëmero 17 de la serie "Primitivos" en servicio en la tranviaria l‚îú¬°nea de Torrero.', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64524900, -0.88581500, '0101000020E6100000B8CCE9B29858ECBF6B63EC8497D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54218344204.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54218344204.webp', 'https://www.flickr.com/photos/zaragozaantigua/54218344204/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24978, 'Jos‚îú¬Æ Luis Violeta 1978', 'El futbolista Jos‚îú¬Æ Luis Violeta (Zaragoza, 1941) alza un trofeo con la reproducci‚îú‚îÇn de la estatua del Augusto de Prima Porta, durante su homenaje en el campo de f‚îú‚ïëtbol de La Romareda, el 21 de mayo de 1978. "El Le‚îú‚îÇn de Torrero" hab‚îú¬°a jugado en el Real Zaragoza durante 14 temporadas (1963-1977). Fuente visual: www.resultados-futbol.com/foto/jose-luis-violeta_711077', 1978, 1978, 1978, 'Anos 70', 'UNIVERSIDAD', 41.63637700, -0.90173500, '0101000020E6100000EC12D55B03DBECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21961617041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21961617041.webp', 'https://www.flickr.com/photos/zaragozaantigua/21961617041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21384, 'P.‚î¨‚ïë de Sagasta 1915', '"Calle. Hombre" (sic). Imagen del arranque del Paseo de Sagasta. El se‚îú‚ñíor con canotier est‚îú√≠ bajando por la larga acera del Colegio del Sagrado Coraz‚îú‚îÇn, a punto de llegar a la glorieta del monumento al reducto del Pilar. Al otro lado del arbolado paseo, algunos de los edificios de los pares, con sus peculiares y exclusivos retranqueos cerrados con verjas (algunos, ajardinados). En la acera de los n‚îú‚ïëmeros impares, los edificios se aferraron a la linealidad del muro del colegio, y se negaron a retranquearse, ganando un espacio extra "gratis et amore", como s‚îú‚îÇlo era posible cuando las familias de la alta sociedad eran, a la vez, quienes hac‚îú¬°an y deshac‚îú¬°an las cosas del Ayuntamiento. Los curiosos entrantes y salientes del desigual lado oriental del paseo se podr‚îú¬°an explicar en funci‚îú‚îÇn del apellido del propietario-concejal afectado. Cosas del sistema pol‚îú¬°tico de la Restauraci‚îú‚îÇn Borb‚îú‚îÇnica. Buena ma‚îú‚ñíana para pasear, si se‚îú‚ñíor. Por el paseo baja un peque‚îú‚ñío cauce residual por gravedad. Los ra‚îú¬°les del tranv‚îú¬°a de Torrero van por el centro del paseo, para no molestar a los 200 veh‚îú¬°culos a motor de explosi‚îú‚îÇn matriculados en la ciudad, y provocar as‚îú¬° un caos civilizatorio. Fuente visual: AHPZ-Archivo Coyne.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64582700, -0.88585800, '0101000020E61000008ACC5CE0F258ECBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16885321574.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16885321574.webp', 'https://www.flickr.com/photos/zaragozaantigua/16885321574/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23784, 'Alfocea 1999', 'El barrio rural de Alfocea, en una vista con los montes del Castellar al fondo. Protagoniza la imagen la barroca iglesia parroquial de la Inmaculada Concepci‚îú‚îÇn, construida en 1683 y adosada a un anterior templo rom‚îú√≠nico que fue demolido en 1974. Este barrio zaragozano, que fue pueblo independiente hasta 1887, tiene como ‚îú‚ïënico acceso un puente construido sobre el r‚îú¬°o Ebro en 1968, proyectado por el ingeniero oscense Juan Jos‚îú¬Æ Arenas, que lo comunica con Monzalbarba.', 1999, 1999, 1999, 'Anos 90', NULL, 41.72409100, -0.95090700, '0101000020E6100000F8325184D46DEEBFFA298E03AFDC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50199320841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50199320841.webp', 'https://www.flickr.com/photos/zaragozaantigua/50199320841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21400, 'P.‚î¨‚ïë de Sagasta c.1912', 'Imagen del arranque del paseo de Sagasta encaminado en direcci‚îú‚îÇn sur, tras el cruce del puente de Santa Engracia. A la derecha, el vel‚îú‚îÇdromo de los El‚îú¬°seos y las primeras viviendas de este ascendente ensanche burgu‚îú¬Æs. A la izquierda, el peque‚îú‚ñío obelisco instalado en 1909 en la Glorieta de P‚îú¬Ærez Gald‚îú‚îÇs (luego, Sasera) en recuerdo a los irreductibles del reducto del Pilar, con la necrof‚îú¬°lica inscripci‚îú‚îÇn "Morir por la Virgen del Pilar o vencer". Tras la foresta, el colegio del Salvador de los PP. Jesuitas, y el de las religiosas del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës, o "francesas". Entre ambos, el paseo de las Damas. A pesar de tratarse de un ensanche burgu‚îú¬Æs, este paseo carecer‚îú¬°a de alcantarillado hasta unos a‚îú‚ñíos despu‚îú¬Æs, cuando se aprobara y realizara el proyecto de Yarza, y el firme no estaba pavimentado. Por el centro del paseo, todav‚îú¬°a el tendido viario de la electrificada l‚îú¬°nea de Torrero.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.64588300, -0.88557900, '0101000020E6100000C1C760C5A956ECBF6C054D4BACD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22937594986.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22937594986.webp', 'https://www.flickr.com/photos/zaragozaantigua/22937594986/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21521, 'P.‚î¨‚ïë de Sagasta 1923', '"Entierro Valenzuela", Julio Requejo, 1923. Entierro de Rafael de Valenzuela y Urzaiz, militar muerto durante la africana guerra colonial del Rif (Protectorado Espa‚îú‚ñíol de Marruecos). En la imagen, perspectiva del f‚îú¬Æretro a la espera del inicio del ceremonial recorrido en el principio del Paseo de Sagasta. En este caso, el objetivo ha tomado como fondo el edificio del Colegio del Salvador, a la derecha, y un paseo muy tranquilo, con ni‚îú‚ñíos jugando. A la izquierda, lejana imagen de los edificios de la plaza de Arag‚îú‚îÇn. Fuente: AHPZ.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64582700, -0.88585800, '0101000020E61000008ACC5CE0F258ECBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16522049729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16522049729.webp', 'https://www.flickr.com/photos/zaragozaantigua/16522049729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21626, 'Cubrimiento Huerva 1926', 'Imagen capturada a nivel del r‚îú¬°o Huerva durante las obras de la primera fase de su cubrimiento en el tramo urbano desde la plaza de Para‚îú¬°so hasta la curva de la Veneciana (unos 450 metros de largo). Era una de las actuaciones para el desarrollo del acceso al ensanche de Miralbueno y el Parque de Zaragoza o de Buenavista. El cauce fluvial ya ha sido modificado para recibir el cubrimiento mediante la construcci‚îú‚îÇn de dos muros de contenci‚îú‚îÇn de hormig‚îú‚îÇn en masa de unos ocho metros de altura en los que se han insertado unas m‚îú¬Ænsulas donde apoyar las vigas de hormig‚îú‚îÇn armado de catorce metros de luz. Al fondo se siluetea el antiguo puente de Santa Engracia bajo la plaza del Para‚îú¬°so. En superficie, el nuevo vial resultante ser‚îú√≠ denominado en un primer momento Gran V‚îú¬°a. Consecuencia inmediata de ello fue la conversi‚îú‚îÇn de la plaza de Para‚îú¬°so en el punto de encuentro de hasta cinco grandes v‚îú¬°as de tr‚îú√≠nsito (los paseos de Independencia, Pamplona y Sagasta, y los dos nuevos viales resultado del cubrimiento), lo que a corto plazo deriv‚îú‚îÇ en su conversi‚îú‚îÇn en una mera rotonda de tr‚îú√≠fico rodado con graves problemas de movilidad que perduran en el tiempo. Cierta lectura m‚îú√≠s profunda de la g‚îú¬Ænesis y desarrollo del cubrimiento del Huerva vincular‚îú¬°a el proyecto a los ritmos de los intereses especulativos del sector propietario e inmobiliario que buscaban aumentar las expectativas urban‚îú¬°sticas de los terrenos comprendidos entre la plaza de Para‚îú¬°so y el parque de Buenavista, hasta entonces convenientemente mantenidos en situaci‚îú‚îÇn de barbecho. Fuente visual: ‚îú√ºngel A‚îú¬°sa y Hermano.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64598300, -0.88860200, '0101000020E61000004B2025766D6FECBFD0622992AFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35950343474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35950343474.webp', 'https://www.flickr.com/photos/zaragozaantigua/35950343474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22134, 'Callej‚îú‚îÇn de Rod‚îú‚îÇn 1951', 'Imagen capturada desde el arbolado paseo de las Damas (antiguo de Sasera) y centrada en el principio del desaparecido callej‚îú‚îÇn de Rod‚îú‚îÇn (actual calle de San Ignacio de Loyola), as‚îú¬° denominado por la presencia de la importante fundici‚îú‚îÇn de Rod‚îú‚îÇn (a la izquierda). Este sinuoso camino serpenteaba entre torres y huertos de las Adulas (a la derecha), el colegio del Salvador, diversos talleres y almacenes industriales, hasta desembocar cerca del camino de los Pl‚îú√≠tanos. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64590100, -0.88470900, '0101000020E61000007842AF3F894FECBF13BA4BE2ACD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23972165597.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23972165597.webp', 'https://www.flickr.com/photos/zaragozaantigua/23972165597/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22384, 'Glorieta Sasera c.1968', 'Glorieta de Sasera, junto al monumento en homenaje al √î√á¬£Reducto del Pilar√î√á√ò. Detr‚îú√≠s, el colegio del Sagrado Coraz‚îú‚îÇn. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64588300, -0.88527900, '0101000020E61000001BBD1AA03454ECBF6C054D4BACD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22522215923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22522215923.webp', 'https://www.flickr.com/photos/zaragozaantigua/22522215923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22402, 'P.‚î¨‚ïë del General Mola 1967', 'Entrada del cine Mola en el n‚îú‚ïëmero 12 del paseo del mismo nombre. Fue inaugurado el 16 de febrero de 1967 seg‚îú‚ïën proyecto de Antonio Ch‚îú‚îÇliz y clausurado el 7 de abril de 2005. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64582700, -0.88585800, '0101000020E61000008ACC5CE0F258ECBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23613113652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23613113652.webp', 'https://www.flickr.com/photos/zaragozaantigua/23613113652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22513, 'P‚î¨‚ïë. del General Mola c.1960', 'Imagen centrada en la placa cer‚îú√≠mica que identificaba la glorieta de Sasera a la izquierda del paseo del General Mola, adosada al muro perimetral del gran colegio del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës, cuyos altos vol‚îú‚ïëmenes sobresalen al fondo.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64556200, -0.88549300, '0101000020E61000001DC87A6AF555ECBF2AC58EC6A1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51354380931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51354380931.webp', 'https://www.flickr.com/photos/zaragozaantigua/51354380931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22688, 'Glorieta de Sasera c.1971', 'Apoteosis del baturrismo costumbrista, en la glorieta de Sasera. Al fondo, paseo del General Mola. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.64580900, -0.88525800, '0101000020E61000003DB7D0950854ECBF323B8BDEA9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26812122123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26812122123.webp', 'https://www.flickr.com/photos/zaragozaantigua/26812122123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23786, 'Conservas Marraco 1908', 'Imagen capturada en el interior de la f‚îú√≠brica de conservas vegetales de Marraco Hermanos, sita en Monzalbarba. Ubicada cerca de la estaci‚îú‚îÇn ferroviaria Utebo-Monzalbarba, contaba con cultivos propios. Empez‚îú‚îÇ su actividad en 1895, y entre sus especialidades estaban los guisantes al estilo franc‚îú¬Æs y el pur‚îú¬Æ de tomate concentrado por evaporaci‚îú‚îÇn al vac‚îú¬°o.', 1908, 1908, 1908, 'Anos 1900', NULL, 41.70046300, -0.98148100, '0101000020E6100000ECA694D74A68EFBF6E8786C5A8D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53818476910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53818476910.webp', 'https://www.flickr.com/photos/zaragozaantigua/53818476910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22717, 'P.‚î¨‚ïë de Sagasta 1979', 'Imagen capturada en el arranque del paseo de Sagasta durante el derribo del antiguo colegio del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës, en esa ubicaci‚îú‚îÇn desde 1875. Teodoro R‚îú¬°os Balaguer proyecto buena parte de su f‚îú√≠brica, luego ampliada. Como en otros casos en la ciudad, a comienzos de los a‚îú‚ñíos setenta del pasado siglo, y dentro de la no oficial "Operaci‚îú‚îÇn Colegios Privados", este inmenso colegio fue desalojado, derribado, y sobre su solar se construyeron nuevos referentes de la Zaragoza postmoderna: un complejo residencial, y una gran superficie comercial. El colegio de nueva planta, de esta franquicia, llevaba funcionando desde 1975 en el entonces despoblado norte de la ciudad, junto a la avenida de los Pirineos. En la imagen, derribo del colegio en su parte delimitada entre el paseo de Sagasta, desde donde se ha hecho la foto; la glorieta de Sasera, a la izquierda, de donde emerge la gr‚îú‚ïëa; y el paseo de las Damas, al fondo, donde aparecen las fachadas de los n‚îú‚ïëmeros 5, y 7, de esa calle. En primer plano, un pedazo de muro por donde algo m‚îú√≠s tarde se abrir‚îú¬°a la conexi‚îú‚îÇn con la calle Le‚îú‚îÇn XIII, y en ese muro, un recuerdo del paso por Zaragoza de la "ballena gigante Jon‚îú√≠s", tra‚îú¬°da desde el Atl‚îú√≠ntico norte por Adena-WWF durante la campa‚îú‚ñía "Los mares deben vivir". Fuente visual: Gerardo Sancho Ramo, en AMZ/ES. 50297. AM 04.01.02.11 Carpeta conservaci‚îú‚îÇn 25081', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.64497900, -0.88548100, '0101000020E61000000C570740DC55ECBFABCDFFAB8ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30099935246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30099935246.webp', 'https://www.flickr.com/photos/zaragozaantigua/30099935246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22906, 'Sala En Bruto 1989', 'Posado del grupo vallisoletano The Bumpers en la puerta de la sala de conciertos En Bruto, inaugurada en 1986 en la calle Comandante Santa Pau 1 de Zaragoza. Tras un concierto all‚îú¬° de H‚îú¬Æroes del silencio en 1987, este grupo firm‚îú‚îÇ su contrato con una multinacional. Desde 2009, la calle se denomina H‚îú¬Æroes del silencio. Fuente visual: www.valladolidwebmusical.org/bandas/especiales/bumpers/', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.64288300, -0.88474300, '0101000020E61000007DAD4B8DD04FECBFC2137AFD49D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21921962503.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21921962503.webp', 'https://www.flickr.com/photos/zaragozaantigua/21921962503/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23188, 'Gran V‚îú¬°a 2010', '30 de enero de 2010. Acera de los impares en la Gran V‚îú¬°a de Zaragoza, a la altura de su confluencia con la calle Arzobispo Dom‚îú¬Ænech, a la derecha. El r‚îú¬°o Huerva, descubierto por las obras de reforzamiento del firme realizadas ese a‚îú‚ñío. Fuente: www.facebook.com/photo.php?fbid=10203907260380622&set...', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.64593900, -0.88806600, '0101000020E6100000AE105663096BECBF001B1021AED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15371332315.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15371332315.webp', 'https://www.flickr.com/photos/zaragozaantigua/15371332315/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24002, 'Calle Royo c.1962', 'Imagen del portal 5-7 de la calle de Mariano Royo Urieta de Zaragoza, con la entrada de la sala de fiestas Cancela a la izquierda. Este negocio fue abierto en 1962 y cerrado en 1979. Contaba con tres plantas, entre las que se repart‚îú¬°an el sal‚îú‚îÇn de espect‚îú√≠culos, las barras de alterne y los reservados. All‚îú¬° actuaron Estrellita Castro, Antonio Mach‚îú¬°n, Luis Mariano y Josephine Baker.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64556100, -0.88723200, '0101000020E610000098DEFE5C3464ECBF5A492BBEA1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21956341134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21956341134.webp', 'https://www.flickr.com/photos/zaragozaantigua/21956341134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24236, 'P.‚î¨‚ïë del General Mola c.1954', 'Gigantes y Cabezudos durante una pausa procesionaria en el paseo del General Mola, a la altura del emboque a la calle de Mariano de La Gasca, a la izquierda (fuera de plano), junto al hotelito que fuera antigua cl‚îú¬°nica del doctor Lozano, en la solanera del lado de los edificios (sin) pares de ese tramo del paseo, algunos desaparecidos a‚îú‚ñíos despu‚îú¬Æs. Fuente visual: "Zaragoza y sus fiestas".', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64508600, -0.88595700, '0101000020E61000005531957EC259ECBFC18D942D92D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32254938842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32254938842.webp', 'https://www.flickr.com/photos/zaragozaantigua/32254938842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24257, 'Encauzamiento Huerva 1925', 'Comienzo de las obras de encauzamiento del r‚îú¬°o Huerva en el tramo denominado "entre la Veneciana y la Facultad". 1925. A la izquierda, los edificios de la Facultad de Medicina y Ciencias. Al fondo, el puente de Santa Engracia. A la derecha, andamios del nuevo cauce sobre el que cubrir el r‚îú¬°o. En el Plan de Ensanche de 1934 este tramo ser‚îú¬°a denominado "Gran V‚îú¬°a de Pablo Iglesias", uno de los tres nuevos tramos urbanos resultantes del cubrimiento del Huerva. Los otros dos ser‚îú¬°an "Gran V‚îú¬°a de Francisco Giner de los R‚îú¬°os", y "Gran V‚îú¬°a de Gal‚îú√≠n y Garc‚îú¬°a Hern‚îú√≠ndez". Estas denominaciones, tras el 18 de julio de 1936, tuvieron ef‚îú¬°mera vida, como la de quienes las propusieron.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64576200, -0.88905500, '0101000020E6100000890CAB782373ECBFF17F4754A8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14978040218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14978040218.webp', 'https://www.flickr.com/photos/zaragozaantigua/14978040218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25079, 'Tina Turner 1990', 'Actuaci‚îú‚îÇn de la cantante estadounidense Tina Turner (1939) en La Romareda, el 9 de octubre de 1990, con El ‚îú‚ïëltimo de la fila como teloneros. Fuente: Agencia EFE.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63637700, -0.90173500, '0101000020E6100000EC12D55B03DBECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24519754352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24519754352.webp', 'https://www.flickr.com/photos/zaragozaantigua/24519754352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25081, 'James Brown 1988', 'EL 12 de octubre de 1988, el cantante estadounidense James Brown (1933-2006) actu‚îú‚îÇ en La Romareda, con el grupo espa‚îú‚ñíol La Uni‚îú‚îÇn como teloneros. Fuente: Agencia EFE.', 1988, 1988, 1988, 'Anos 80', 'UNIVERSIDAD', 41.63637700, -0.90173500, '0101000020E6100000EC12D55B03DBECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24627468385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24627468385.webp', 'https://www.flickr.com/photos/zaragozaantigua/24627468385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25596, 'Feria de Muestras 1955', 'Vista del entorno del recinto de la Feria de Muestras, desde las alturas de la "Residencia Sanitaria Jos‚îú¬Æ Antonio". A la izquierda, el Campus de San francisco, con la Facultad de Filosof‚îú¬°a y Letras. Al fondo, el nov‚îú¬°simo edificio de Regino Borobio Ojeda para la √î√á¬£Escuela de Maestr‚îú¬°a Industrial de Zaragoza√î√á√ò y la "Escuela T‚îú¬Æcnica de Peritos Industriales" (actual CPIFP Corona de Arag‚îú‚îÇn). En el centro, imagen del Paseo de Fernando el Cat‚îú‚îÇlico ya casi totalmente construido en lo que a viviendas se refiere. Aparcamientos en superficie, y en bater‚îú¬°a, una rareza que nunca m‚îú√≠s se volver‚îú√≠ a ver en esa ubicaci‚îú‚îÇn. A la derecha, el Puente 13 de setiembre, y el acceso al Parque Primo de Rivera, donde est‚îú√≠ en obras la "Casa Ansotana", cuya primera piedra se hab‚îú¬°a puesto en abril de este a‚îú‚ñío, y ser‚îú√≠ inaugurada en marzo del a‚îú‚ñío siguiente. M‚îú√≠s adelante, la significada torre del complejo de la Editorial Luis Vives. Al fondo, el skyline de la ciudad hist‚îú‚îÇrica, con La Casa de Misericordia, San Pablo, Santiago el Mayor, y la bas‚îú¬°lica del Pilar, con las dos torres ribere‚îú‚ñías en ascenso.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63753600, -0.89840000, '0101000020E6100000AB3E575BB1BFECBFE60297C79AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14804299308.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14804299308.webp', 'https://www.flickr.com/photos/zaragozaantigua/14804299308/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24261, 'Camino del S‚îú√≠bado 1930', 'Imagen del nov‚îú¬°simo n‚î¨‚ïë 17 de la Gran V‚îú¬°a, dise‚îú‚ñíado en 1930 por Jos‚îú¬Æ y Regino Borobio para Isidoro Mart‚îú¬°nez Ortiz, como primer y, de momento, aislado edificio construido en el eje de desarrollo de este nuevo vial de la ciudad, tras el recubrimiento del urbano tramo del r‚îú¬°o Huerva que por aqu‚îú¬° fluye. La imagen est‚îú√≠ capturada desde las traseras del edificio, en el antiguo Camino del S‚îú√≠bado, junto a una acequia que desaguaba en el Huerva, y cuyo sinuoso recorrido explica el irregular trazado de los muros que delimitaban esta propiedad, y los de las huertas de la zona. La fachada principal, y ‚îú¬Æsta trasera, son dispares en altura: desde este trasero y sabatino punto de vista, se trataba de un enorme edifico de ocho plantas de altura (7+bajos), adem‚îú√≠s de un pl‚îú√≠stico ‚îú√≠tico. Desde la Gran V‚îú¬°a, el edificio parece "encoger" al menos dos pisos, como consecuencia de la importante diferencia de altura que el recubrimiento del r‚îú¬°o hab‚îú¬°a establecido entre ambos puntos: los muros del fondo, a ambos lados del edifico, indican el horizonte establecido por la "caja" que cubr‚îú¬°a el r‚îú¬°o, a la que se sumaba el murete de protecci‚îú‚îÇn para evitar ca‚îú¬°das, hasta que los solares de sus medianeras fueron construidos. A‚îú‚ñíos despu‚îú¬Æs, el remate del edificio ser‚îú¬°a modificado y convertido en una nueva planta completa, perdiendo con ello su caracter‚îú¬°stica y art‚îú¬°stica veleta. El tranquilo riego con manguera del patio trasero, tal que si fuera un adosado de las Adulas, "avant la lettre ". Fuente visual: foto Miguel Mar‚îú¬°n Chivite, en "Una mirada a trav‚îú¬Æs de la arquitectura: Regino y Jos‚îú¬Æ Borobio Ojeda", de Daniel Estab‚îú¬Æn Boldova.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64576400, -0.88802400, '0101000020E6100000F304C24EB16AECBF92770E65A8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24647321235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24647321235.webp', 'https://www.flickr.com/photos/zaragozaantigua/24647321235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24543, 'P‚î¨‚ïë de Sagasta c.1914', 'Imagen capturada en el interior de la f‚îú√≠brica de camas de hierro de la Viuda de Irisarri, sita en el n‚î¨‚ïë 10 del paseo de Sagasta Esta fue la tercera de las ubicaciones urbanas de esta f‚îú√≠brica, fundada originalmente en 1860 por Miguel Irisarri en la calle Don Jaime I. En 1887 comenzaron las gestiones para construir esta f‚îú√≠brica en el entonces camino de Torrero, en un solar de los Campos El‚îú¬°seos, donde perdur‚îú‚îÇ hasta que en 1927 se traslad‚îú‚îÇ a la calle del Castillo. En la imagen, una de las camas producidas en esta factor‚îú¬°a, que en la d‚îú¬Æcada de los a‚îú‚ñíos 10 conoci‚îú‚îÇ la introducci‚îú‚îÇn de mejoras como dorarlas al fuego y barnizarlas con esmalte, que redundaban en la perdurabilidad del producto. Esta f‚îú√≠brica conoci‚îú‚îÇ a principios de esta misma d‚îú¬Æcada un importante conflicto protagonizado por sus obreros metal‚îú‚ïërgicos.', 1914, 1914, 1914, 'Anos 10', 'CENTRO', 41.64582700, -0.88585800, '0101000020E61000008ACC5CE0F258ECBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53455093699.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53455093699.webp', 'https://www.flickr.com/photos/zaragozaantigua/53455093699/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24901, 'P.‚î¨‚ïë del General Mola 1947', 'Gran edificio administrativo situado en el paseo del General Mola n‚î¨‚ïë 24, para albergar las oficinas de la Confederaci‚îú‚îÇn Hidrogr‚îú√≠fica del Ebro. Proyecto racionalista ejemplar, firmado por los hermanos Borobio. Fuente visual: "Regino y Jos‚îú¬Æ Borobio Ojeda", Ayuntamiento de Zaragoza, 1991.', 1947, 1947, 1947, 'Anos 40', 'CENTRO', 41.64471200, -0.88597600, '0101000020E6100000054F2157EA59ECBF5CAB3DEC85D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15533616425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15533616425.webp', 'https://www.flickr.com/photos/zaragozaantigua/15533616425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24927, 'Glorieta de Sasera 1963', 'Imagen capturada en la glorieta de Sasera. y centrada en el decimom‚îú‚îÇnico grupo escult‚îú‚îÇrico instalado ese a‚îú‚ñío en bronce como homenaje a los defensores del Reducto del Pilar durante el asedio franc‚îú¬Æs en 1809, que culmin‚îú‚îÇ con la toma del reducto y la capitulaci‚îú‚îÇn de la ciudad. Originalmente realizado en yeso por el escultor Federico Amutio y Amil en 1892, fue adquirido por el Ayuntamiento en una versi‚îú‚îÇn en bronce que primero estuvo en la Casa Consistorial de la plaza de Santo Domingo, y que en 1963 fue ubicado en esta localizaci‚îú‚îÇn para sustituir al obelisco realizado por Ricardo Magdalena que desde 1908 fue el original monumento a los defensores del Reducto del Pilar. De esta forma, el obelisco fue retirado y demolido, y en su lugar se emplaz‚îú‚îÇ esta escultura que en principio estaba dedicada a dos combatientes an‚îú‚îÇnimos de la guerra contra Francia, sin especificar su ubicaci‚îú‚îÇn. Presenta la inscripci‚îú‚îÇn en el pedestal que reza "Por la Virgen del Pilar. Vencer o morir. MDCCCVIII", y el acompa‚îú‚ñíamiento de un par de ca‚îú‚ñíones de ‚îú¬Æpoca. Tras el monumento, muro perimetral del tradicional colegio del Sagrado Coraz‚îú‚îÇn recayente a la glorieta, adem‚îú√≠s de modernos inmuebles en el arranque del paseo del General Mola.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64581100, -0.88527900, '0101000020E61000001BBD1AA03454ECBFD33252EFA9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50343761923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50343761923.webp', 'https://www.flickr.com/photos/zaragozaantigua/50343761923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25019, 'Obelisco Reducto del Pilar 1909', 'AHPZ. Archivo Coyne. 1909. Con posterioridad a la Exposici‚îú‚îÇn Hispano-Francesa de 1908, en la Glorieta Sasera se instal‚îú‚îÇ un peque‚îú‚ñío obelisco dise‚îú‚ñíado por Ricardo Magdalena con el que recordar a los defensores del reducto del Pilar, con la incalificable inscripci‚îú‚îÇn "Morir por la Virgen del Pilar o vencer. A los heroicos defensores del reducto del Pilar. Primer centenario de Los Sitios. 1908." En la imagen, aspecto de la institucional ceremonia de inauguraci‚îú‚îÇn del obelisco en la Glorieta de P‚îú¬Ærez Gald‚îú‚îÇs (luego redenominada de Sasera), a finales del mes de enero. Hay autoridades (con sombrero de copa), funcionarios municipales (disfrazados de maceros, para dar ambiente), y p‚îú‚ïëblico en general. El muro del fondo protege al colegio de los PP. Jesuitas.', 1909, 1909, 1909, 'Anos 1900', 'CENTRO', 41.64588300, -0.88527900, '0101000020E61000001BBD1AA03454ECBF6C054D4BACD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15043782215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15043782215.webp', 'https://www.flickr.com/photos/zaragozaantigua/15043782215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25024, 'Avenida de la Rep‚îú‚ïëblica 1936', '"Sanatorio Lozano : Vista del porche y jard‚îú¬°n". En 1903 el arquitecto F‚îú¬Ælix Navarro proyect‚îú‚îÇ un nuevo edificio para vivienda y cl‚îú¬°nica del doctor Lozano en el ensanche burgu‚îú¬Æs del paseo de Sagasta (esquina con Lagasca). Pocos a‚îú‚ñíos despu‚îú¬Æs fue objeto de la primera de las bastantes reformas que desvirtuaron un tanto el proyecto de Navarro aunque, al menos, supervive, lo que no es poco, trat‚îú√≠ndose de Zaragoza. Se trat‚îú‚îÇ de la reforma de Manuel del Busto, que en 1916 ampli‚îú‚îÇ y reform‚îú‚îÇ su aspecto, dej‚îú√≠ndolo como la imagen muestra. En 2009 el edificio fue declarado "bien del patrimonio cultural aragon‚îú¬Æs", cuando ya una promotora inmobiliaria ten‚îú¬°a fumata blanca de la comisi‚îú‚îÇn provincial de Patrimonio para levantar en sus jardines un bloque de viviendas de doce alturas. En 2013, el Tribunal Superior de Justicia de Arag‚îú‚îÇn anul‚îú‚îÇ el proyecto por cuestiones vinculadas a la iluminaci‚îú‚îÇn, ventilaci‚îú‚îÇn, dimensiones de los patios y distancias respecto a otros edificios. El Ayuntamiento recurri‚îú‚îÇ al Tribunal Supremo, que a‚îú‚ïën no se ha pronunciado. Hace poco, el Ayuntamiento requiri‚îú‚îÇ a la propiedad del inmueble la realizaci‚îú‚îÇn de una serie de actuaciones relacionadas con la seguridad del edificio, para evitar afecciones a la v‚îú¬°a p‚îú‚ïëblica. De resultas de ello, el edificio se encuentra rodeado de andamios y malla pl‚îú√≠stica de obra. En la imagen, aspecto del "Sanatorio Lozano" capturado desde la Avenida de la Rep‚îú‚ïëblica. A la izquierda, la calle de La Gasca. Siquiera parcialmente, a‚îú‚ïën es visible el remate en forma de torrecilla bulbosa que, dise‚îú‚ñíada por Navarro, posteriores reformas han eliminado. Y abajo, a al derecha, un pedacito de los antiguos y p‚îú¬Ætreos bancos de la Avenida. Fuente visual: www.bancodeimagenesmedicina.es/', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64496900, -0.88607300, '0101000020E6100000A3CB9BC3B55AECBF88F71C588ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17176022199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17176022199.webp', 'https://www.flickr.com/photos/zaragozaantigua/17176022199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25031, 'P.‚î¨‚ïë del General Mola 1938', 'Imagen capturada por un soldado alem‚îú√≠n de la Legi‚îú‚îÇn C‚îú‚îÇndor, centrada en el edificio de la Confederaci‚îú‚îÇn Hidrogr‚îú√≠fica del Ebro, dise‚îú‚ñíada por Regino y Jos‚îú¬Æ Borobio, cuya construcci‚îú‚îÇn se hab‚îú¬°a iniciado en 1936, cuando esta era la avenida de la Rep‚îú‚ïëblica. Ahora, tras el golpe del 18-19 de julio de ese a‚îú‚ñío, hab‚îú¬°a sido redenominada "paseo del General Mola". Esta manzana, delimitada por las calles de Mariano Lagasca (inmediata, a la derecha), y Cervantes, se completaba con el edificio del n‚î¨‚ïë 30, realizado la anterior d‚îú¬Æcada con proyecto de Teodoro R‚îú¬°os Balaguer. A continuaci‚îú‚îÇn, y esquinera con la calle de Cervantes, la desaparecida casa de los Escoriaza-Averly, dise‚îú‚ñíada por Luis de La Figuera. Entre los adoquines de la calzada, las v‚îú¬°as de la l‚îú¬°nea del tranv‚îú¬°a de Torrero. Fuente visual: www.ebay.es/', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64471200, -0.88597600, '0101000020E6100000054F2157EA59ECBF5CAB3DEC85D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31033523395.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31033523395.webp', 'https://www.flickr.com/photos/zaragozaantigua/31033523395/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25034, 'P.‚î¨‚ïë de Sagasta 1899', 'Imagen de la fachada y el acceso desde el paseo de Sagasta a la f‚îú√≠brica de camas de hierro y lat‚îú‚îÇn de Miguel Irisarri L‚îú‚îÇpez de Goicoechea. Fundada en 1860 en la calle Don Jaime I, desde 1887 estaba en esta ubicaci‚îú‚îÇn del antiguo camino de Torrero, entre el terreno denominado Campos El‚îú¬°seos y el Huerto y torre de Val (a la izquierda de la imagen), en unas instalaciones mucho m‚îú√≠s amplias y modernas. Miguel Irisarri muri‚îú‚îÇ en 1902, si bien la f‚îú√≠brica continu‚îú‚îÇ aqu‚îú¬° hasta que en 1927 fue trasladada al barrio del Castillo. Al fondo, a la derecha, el torre‚îú‚îÇn sureste del reciente edificio de las Facultades de Medicina y Ciencias. Fuente visual: posiblemente foto Coyne, en "Arag‚îú‚îÇn Ilustrado" n‚î¨‚ïë 2 (7 de enero de 1899).', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64582700, -0.88585800, '0101000020E61000008ACC5CE0F258ECBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31631442273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31631442273.webp', 'https://www.flickr.com/photos/zaragozaantigua/31631442273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25052, '&quot;Las francesas&quot; c.1935', 'Abanderado posado colectivo de alumnas capturado en el patio de recreo del colegio de las religiosas del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës, popularmente denominadas "las francesas", sito en la avenida de la Rep‚îú‚ïëblica (antiguo paseo de Sagasta) desde 1875.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64471400, -0.88485900, '0101000020E6100000CB4752D2C350ECBFFDA204FD85D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52386103204.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52386103204.webp', 'https://www.flickr.com/photos/zaragozaantigua/52386103204/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20910, 'Campo del Toro 1777', 'Plano del Campo del Toro y sus inmediaciones, en el que se demuestra el terreno sobre el que se han hecho y levantado planos para quarteles y el terreno que la Misericordia ha ocupado del uno. 12 de enero de 1777. Archivo General de Simancas. Croquis del entorno de la plaza de toros de Zaragoza poco despu‚îú¬Æs de su construcci‚îú‚îÇn, en 1764.Todos los elementos representados exist‚îú¬°an previamente, excepto los dos cuarteles proyectados junto a la plaza, en color marr‚îú‚îÇn claro, que no llegaron a levantarse.', 1777, 1777, 1777, 'Siglo XIX', 'CENTRO', 41.65430000, -0.89160400, '0101000020E6100000F7729F1C0588ECBFEBE2361AC0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15457421447.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15457421447.webp', 'https://www.flickr.com/photos/zaragozaantigua/15457421447/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20994, 'Plaza de Toros 1816', '"Temeridad de Martincho en la plaza de Zaragoza". Tauromaquia, 18. Aguafuerte sobre papel. Francisco de Goya y Lucientes, 1816. Una de las estampas de la serie grabada por Goya entre la primavera de 1814 y el oto‚îú‚ñío de 1816. Representa un lance del torero Martincho (Francisco Antonio Ebass‚îú‚ïën Mart‚îú¬°nez, 1708-1772) realizado en la plaza de Toros de Zaragoza muchas d‚îú¬Æcadas antes. A la izquierda, junto al toril, unos cuantos zaragozanos grotescos observan la audaz acrobacia. Fuente: Museo del Prado.', 1816, 1816, 1816, 'Siglo XIX', 'CENTRO', 41.65448600, -0.89193500, '0101000020E61000005F0CE544BB8AECBF4DD87E32C6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31371413243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31371413243.webp', 'https://www.flickr.com/photos/zaragozaantigua/31371413243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21368, 'Plaza de Toros c.1915', 'Puerta Principal de la Misericordia de Zaragoza, Luis Gand‚îú‚ïë Mercadal, entre 1912 y 1916. La puerta principal de la plaza coincide en su ubicaci‚îú‚îÇn con la actual Puerta Grande. En la cubierta, la buhardilla alineada. Fuente visual: El coso de la Misericordia de Zaragoza (2014).', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65428400, -0.89152200, '0101000020E6100000AF4335255987ECBFE525FF93BFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15023574983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15023574983.webp', 'https://www.flickr.com/photos/zaragozaantigua/15023574983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21467, 'Coso de la Misericordia 1913', 'Imagen interior del Coso de la Misericordia centrada en la umbr‚îú¬°a Puerta de Arrastres, donde destaca el "balc‚îú‚îÇn" sobre ‚îú¬Æl habilitado. La pervivencia del t‚îú¬Ærmino "balc‚îú‚îÇn" recuerda la original celebraci‚îú‚îÇn de este tipo de espect‚îú√≠culos en la plaza del Mercado, cuando se utilizaban los balcones de las casas para acoger al p‚îú‚ïëblico asistente de m‚îú√≠s poder de adquisici‚îú‚îÇn y estatus social. La estructura y aspecto de este coso apenas hab‚îú¬°a variado en lo fundamental desde su construcci‚îú‚îÇn finalizada en 1765, conservando por ejemplo las arquer‚îú¬°as dieciochescas de madera que se elevan desde la grada cubierta hasta los palcos. S‚îú¬° hab‚îú¬°a cambiado el firme del tendido o gradas, donde la piedra de siller‚îú¬°a sustituy‚îú‚îÇ a la original madera, adem‚îú√≠s de la introducci‚îú‚îÇn de las barandillas de hierro, seg‚îú‚ïën reforma acometida entre 1877 y 1892. La escena muestra la plaza atestada de p‚îú‚ïëblico, destacando los muy distintos perfiles sociales entre quienes de sientan sobre el p‚îú¬Ætreo tendido y quienes ocupan el balc‚îú‚îÇn, que aparece decorado con motivos vegetales, adem‚îú√≠s de con los mantones de Manila de las "mujeres bonitas y requetepreciosas" que lo ocupan. Decorando la parte superior de los pilares que sustentan el palco presidencial, destacan banderas que flanquean cuatro escudos donde aparecen los cuatro cuarteles del escudo de la provincia de Zaragoza (de izquierda a derecha: el ‚îú√ºrbol de Sobrarbe, la Cruz de Alcoraz cantonada con cuatro cabezas de moros, la Cruz de ‚îú√¨‚îú‚ñíigo Arista, y la Se‚îú‚ñíal Real de Arag‚îú‚îÇn con las cuatro barras).', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65433200, -0.89180200, '0101000020E61000008E3C1059A489ECBFF65CA626C1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53459232719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53459232719.webp', 'https://www.flickr.com/photos/zaragozaantigua/53459232719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21705, 'Vista 1938', 'Los pilotos alemanes de la Legi‚îú‚îÇn C‚îú‚îÇndor estacionados en el Aer‚îú‚îÇdromo de Sanjurjo (base a‚îú¬Ærea de Zaragoza), durante su estancia colaboradora con los nacionalistas en la guerra desatada en julio de 1936, de permiso por la ciudad han dejado un apreciable cat‚îú√≠logo de instant‚îú√≠neas por diferentes localizaciones. En esta ocasi‚îú‚îÇn, se han subido al tejado de la "Santa y Real Hermandad de Nuestra Se‚îú‚ñíora del Refugio y Piedad", vulgo "El Refugio", inaugurada en 1932, para tomar unas despejadas im‚îú√≠genes a unas trabajadoras, y uno de ellos les ha capturado desde atr‚îú√≠s. A la izquierda, las dos torrecillas del Convento-noviciado de las Hermanas de la Caridad de Santa Ana. Al fondo, el Pilar. A la derecha, la c‚îú‚ïëpula de la iglesia de Santiago, y el Hospital de Nuestra Se‚îú‚ñíora de Gracia.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65119000, -0.89209100, '0101000020E61000003ACAC16C028CECBFBABDA4315AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15811810008.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15811810008.webp', 'https://www.flickr.com/photos/zaragozaantigua/15811810008/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21979, 'Calle de Pignatelli 1948', 'A la sombra del coso de la Misericordia, una despejada visual de la calle Pignatelli en direcci‚îú‚îÇn al este, con la torre de la iglesia parroquial de Santiago el Mayor al fondo, y su antiguo remate. A la izquierda, el ingreso al cuartel del Parque de Artiller‚îú¬°a. A la derecha, el muro perimetral del hospicio del Hogar Pignatelli. En el suelo perduran los ra‚îú¬°les de la antigua l‚îú¬°nea de Madrid, clausurada en 1942. Fuente visual: foto Juan Mora Insa, AMZ.', 1948, 1948, 1948, 'Anos 40', 'CENTRO', 41.65457500, -0.89077100, '0101000020E6100000F834272F3281ECBFBDE3141DC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25240522930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25240522930.webp', 'https://www.flickr.com/photos/zaragozaantigua/25240522930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22444, 'Vista a‚îú¬Ærea Plaza de Toros 1960', 'Vista a‚îú¬Ærea centrada en la Plaza de Toros, con el barrio de San Pablo abajo. A la izquierda de la Plaza, el Hogar Pignatelli; a su derecha, el cuartel del Cid. Al fondo, la estaci‚îú‚îÇn de Campo Sepulcro. Fuente: TAF Helic‚îú‚ñìpters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65453800, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFA0FEB3E6C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30984031580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30984031580.webp', 'https://www.flickr.com/photos/zaragozaantigua/30984031580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22515, 'Hogar Pignatelli c.1961', 'Imagen del gran patio occidental del Hogar Pignatelli, que vertebraba la zona ocupada por las ni‚îú‚ñías y chicas residentes. En el momento de capturar la imagen, desde la altura del primer piso, un grupo de ni‚îú‚ñías juega con aros entre la zona ajardinada que lo caracterizaba (a diferencia del oriental patio de los ni‚îú‚ñíos y chicos, totalmente despejado), bajo la atenta vigilancia de varias hermanas de la caridad de Santa Ana.', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.65348300, -0.89126500, '0101000020E6100000DA38622D3E85ECBFF9BEB854A5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51407329330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51407329330.webp', 'https://www.flickr.com/photos/zaragozaantigua/51407329330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22796, 'P.‚î¨‚ïë de Mar‚îú¬°a Agust‚îú¬°n 1975', 'Imagen centrada en los bajos comerciales ocupados por Sala Rono, referencial establecimiento musical creado y dirigido por el casbasino Mariano Gracia Escario, en su moderna ubicaci‚îú‚îÇn del paseo de Mar‚îú¬°a Agust‚îú¬°n n‚î¨‚ïë 22, local, en uno de los bloques para funcionarios all‚îú¬° construidos inmediato a los Talleres del Hogar Pignatelli. Esta tienda de instrumentos musicales especializada en pianos, armon‚îú¬°a y ‚îú‚îÇrganos, tuvo una primera ubicaci‚îú‚îÇn localizada desde 1938 en el n‚î¨‚ïë 13 de la calle del Doctor G‚îú‚îÇmez Ulla (antigua de la Biblioteca), desaparecida durante el proceso de ensanchamiento de la V‚îú¬°a Imperial, actual avenida de C‚îú¬Æsar Augusto. En 2015 este comercio fue finalmente clausurado. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65168900, -0.89066300, '0101000020E6100000603B18B14F80ECBFDB148F8B6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45190436582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45190436582.webp', 'https://www.flickr.com/photos/zaragozaantigua/45190436582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23100, 'B. B. King 2004', 'El guitarrista y cantante de blues B. B. King (1925-2015), actuando en la plaza de Toros de Zaragoza, el 1 de julio de 2004. Fuente: Agencia EFE.', 2004, 2004, 2004, 'Siglo XXI', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24049053564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24049053564.webp', 'https://www.flickr.com/photos/zaragozaantigua/24049053564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23114, 'Marcelino Iglesias 2003', 'Foto: Jos‚îú¬Æ Miguel Marco. A la derecha, Marcelino Iglesias (PSOE), saludando a su socio Jos‚îú¬Æ ‚îú√ºngel Biel (PAR) durante la campa‚îú‚ñía de las elecciones a Cortes de Arag‚îú‚îÇn de mayo de 2003. Esta pareja gobern‚îú‚îÇ Arag‚îú‚îÇn, como presidente y vicepresidente, entre los a‚îú‚ñíos 1999 y 2011. La instant‚îú√≠nea est‚îú√≠ tomada ante el Edificio Pignatelli, sede del Gobierno de Arag‚îú‚îÇn. Fuente visual: Heraldo de Arag‚îú‚îÇn.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65284600, -0.89175000, '0101000020E6100000F0A7C64B3789ECBF86A92D7590D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30983592134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30983592134.webp', 'https://www.flickr.com/photos/zaragozaantigua/30983592134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23916, 'Cuartel del Cid 1970', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 04/04/1970. Vista de la puerta principal de acceso al abandonado Cuartel de Caballer‚îú¬°a de El Cid. En la actualidad justo aqu‚îú¬° est‚îú√≠ el bloque de viviendas del n‚î¨‚ïë 6 de la calle Benjam‚îú¬°n Jarn‚îú¬Æs. Fue creado por Ram‚îú‚îÇn Pignatelli junto al Coso de la Maestranza y a la Real Casa de la Misericordia. Durante los encuentros b‚îú¬Ælicos entre espa‚îú‚ñíoles y franceses de los a‚îú‚ñíos 1808-1809 fue escenario de ‚îú√≠speros combates. Incluido en la "Operaci‚îú‚îÇn Cuarteles" de los a‚îú‚ñíos 70, casi el 50% de su amplia superficie sigue siendo un solar entre el Paseo de M‚î¨¬¨ Agust‚îú¬°n y la Plaza del Portillo.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65442100, -0.89222600, '0101000020E61000003882548A1D8DECBF66683C11C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754649500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754649500.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754649500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23918, 'Ernest Hemingway 1959', 'Foto: ‚îú√ºlvaro Garc‚îú¬°a Pelayo, 1959. Tres a‚îú‚ñíos antes, en octubre, ya hab‚îú¬°a estado en el Coso de la Misericordia. Ahora, tres a‚îú‚ñíos antes de terminar con su vida, Hemingway regres‚îú‚îÇ a la plaza de toros de Zaragoza, una tarde de agosto de sol, y "buen tiempo", a una tierra que consideraba "absolutamente igual que la m‚îú¬°a" (Illinois, Estados Unidos de Norteam‚îú¬Ærica). Se considera que lo acontecido esa tarde, junto con lo vivido en las de Valencia, M‚îú√≠laga, Bayona, Ciudad Real..., a Hemingway le dio material suficiente para escribir en la revista "LIFE" el art‚îú¬°culo "Verano Sangriento", una cr‚îú‚îÇnica de la temporada toreril espa‚îú‚ñíola de ese a‚îú‚ñío. Fuente: Archivo Fotogr‚îú√≠fico ABC. Cedida por Rafael Castillejo.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65449300, -0.89097000, '0101000020E6100000A6F27684D382ECBF003B376DC6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14857451254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14857451254.webp', 'https://www.flickr.com/photos/zaragozaantigua/14857451254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23920, 'Despeje de la plaza 1793', 'Despeje de la plaza, ‚îú‚îÇleo sobre hojalata, Francisco de Goya, 1793. Colecci‚îú‚îÇn Masaveu, Oviedo. La hasta 2014 considerada representaci‚îú‚îÇn goyesca de la plaza de toros de Madrid, resulta ser la de Zaragoza, seg‚îú‚ïën estudio de Javier Mart‚îú¬°nez y Wifredo Rinc‚îú‚îÇn publicado en el libro El coso de la Misericordia de Zaragoza (2014).', 1793, 1793, 1793, 'Siglo XIX', 'CENTRO', 41.65434800, -0.89154000, '0101000020E6100000486DE2E47E87ECBFFC19DEACC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15023449854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15023449854.webp', 'https://www.flickr.com/photos/zaragozaantigua/15023449854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23925, 'Vista a‚îú¬Ærea 1969', 'A‚îú¬Ærea vista desde el Oeste hacia el centro de la ciudad. En primer plano, el Coso de la Misericordia, la Maternidad e Inclusa, el Hogar Pignatelli, la reciente Jefatura Superior de la Polic‚îú¬°a Armada, el enorme convento de las Hermanas de la Caridad de Santa Ana, y el hospital de N‚î¨¬¨ S‚î¨¬¨ de Gracia. En el entorno de la calle Pignatelli y Madre Rafols, el territorio militar de los cuarteles del Parque de Artiller‚îú¬°a, a la izquierda, y el Cuartel de Sangenis, derecha, a los que se sumaba el cercano de el Cid, y otros. Torres y c‚îú‚ïëpulas van mojoneando la ret‚îú¬°cula urbana: San Pablo, Santiago el Mayor, la Seo, el Pilar... Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65327700, -0.89078800, '0101000020E61000007B6AF5D55581ECBF501DAB949ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15671223760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15671223760.webp', 'https://www.flickr.com/photos/zaragozaantigua/15671223760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23929, 'Vista a‚îú¬Ærea Portillo 1965', 'Vista a‚îú¬Ærea parcial de la zona del Portillo, centrada en el Hogar Pignatelli y el Coso de la Misericordia. Fuente visual : Fotograf‚îú¬°a a‚îú¬Ærea Lecar para el libro "El Ayuntamiento de Zaragoza", Colecci‚îú‚îÇn Rafael Margal‚îú¬Æ.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65396100, -0.89122400, '0101000020E61000003621AD31E884ECBF03EE79FEB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21694053734.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21694053734.webp', 'https://www.flickr.com/photos/zaragozaantigua/21694053734/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23934, 'Cuartel del Cid 1972', '"Antigua puerta de Zaragoza", ‚îú‚îÇleo sobre cart‚îú‚îÇn, J. Benito, 1972. Puerta de acceso principal al Cuartel de Caballer‚îú¬°a del Cid, ya abandonado. La ubicaci‚îú‚îÇn corresponde a la actual calle de Benjam‚îú¬°n Jarn‚îú¬Æs 6. Fuente: www.todocoleccion.net/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65442100, -0.89222600, '0101000020E61000003882548A1D8DECBF66683C11C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25452856253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25452856253.webp', 'https://www.flickr.com/photos/zaragozaantigua/25452856253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23937, 'Coso de la Misericordia 1903', 'Imagen del interior de la antigua plaza de toros de Zaragoza, tambi‚îú¬Æn denominada "Coso de la Misericordia", y hasta "Coso de Pignatelli". Su primera f‚îú√≠brica, provisional, en madera, fue inaugurada en 1764, y perdur‚îú‚îÇ hasta que en el siglo XIX se la reh‚îú¬°zo enteramente en materiales m‚îú√≠s duraderos: piedra y ladrillo, adem‚îú√≠s de madera. Esta es la plaza que aparece en la imagen, que como se trata de una captura fotogr‚îú√≠fica francesa, fue titulada "Les ar‚îú¬ønes". Al fondo, a la izquierda, sobresale la airosa c‚îú‚ïëpula neobizantina de la Casa de la Misericordia. Unos a‚îú‚ñíos m‚îú√≠s tarde, en 1916, este coso ser‚îú√≠ reformado integralmente, d‚îú√≠ndole el aspecto que ha llegado a nosotros. Fuente: www.ebay.es/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26294792534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26294792534.webp', 'https://www.flickr.com/photos/zaragozaantigua/26294792534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23943, 'C‚îú√≠rcel de gitanas 1753', '"Indice o descripci‚îú‚îÇn de este Plan o Fabrica nuevamente construida en la casa de Misericordia de la ciudad de Zaragoza para la Habitaci‚îú‚îÇn de las Gitanas", realizado por el maestro de obras Onofre Graci‚îú√≠n. Se trataba de una nueva construcci‚îú‚îÇn dentro del enorme complejo de la Real Casa de Misericordia como c‚îú√≠rcel de gitanas, durante una de las etapas m‚îú√≠s duras de represi‚îú‚îÇn en Espa‚îú‚ñía contra la etnia gitana a mediados del siglo XVIII. Considerados como pueblo "que no tiene religi‚îú‚îÇn" y raza "malvada", fueron expulsados unos 10000 gitanos de los territorios peninsulares, y se habilitaron c‚îú√≠rceles para gitanas y sus hijos. Esta prisi‚îú‚îÇn estuvo funcional para los objetivos propuestos hasta 1763, con capacidad para varios cientos de personas separadas del resto de residentes a fin de que "esta mala semilla" no pudiera "corromperlos". Su ingreso principal era desde el acceso por el Campo del Toro a la Casa de la Misericordia (a la izquierda del plano), y sus traseras eran recayentes al Campo del Sepulcro. Fuente: Archivos Estatales, Ministerio de Educaci‚îú‚îÇn, Cultura y Deporte de Espa‚îú‚ñía.', 1753, 1753, 1753, 'Siglo XIX', 'CENTRO', 41.65339600, -0.89202600, '0101000020E610000074D0251C7A8BECBF2AABE97AA2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34534841334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34534841334.webp', 'https://www.flickr.com/photos/zaragozaantigua/34534841334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23945, 'El Cordob‚îú¬Æs 1966', 'Imagen capturada en el Coso de la Misericordia, posiblemente durante la Feria del Pilar de ese a‚îú‚ñío, con un primer plano ligeramente desenfocado y mirando a c‚îú√≠mara del popular, heterodoxo y controvertido matador de toros palme‚îú‚ñío Manuel Ben‚îú¬°tez P‚îú¬Ærez, alias El Cordob‚îú¬Æs. A su izquierda, el navarretino y altamente productivo fot‚îú‚îÇgrafo Gerardo Sancho Ramo, reci‚îú¬Æn cumplidos los 55 septiembres, aunando trabajo profesional y taurofilia militante.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65454100, -0.89139400, '0101000020E61000005038BBB54C86ECBF1172DEFFC7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48242100981.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48242100981.webp', 'https://www.flickr.com/photos/zaragozaantigua/48242100981/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23946, 'Hospicio Provincial c.1895', 'A la original y neocl‚îú√≠sica Real Casa de la Misericordia levantada a finales del siglo XVIII en las antiguas Eras del Campo del Toro, en 1867 se le a‚îú‚ñíadi‚îú‚îÇ una neobizantina iglesia con dise‚îú‚ñío del arquitecto Juan Antonio Atienza. En la imagen, fachada principal de la iglesia recayente al rectangular patio de acceso desde el norte. En ella se observa la alternancia de materiales constructivos, que en la parte superior culmina en ladrillo las dos torres que flanquean el ingreso y la singular c‚îú‚ïëpula central.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65337800, -0.89076100, '0101000020E610000015AC71361D81ECBF83F6EAE3A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50087560936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50087560936.webp', 'https://www.flickr.com/photos/zaragozaantigua/50087560936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23947, 'Vista a‚îú¬Ærea c.1962', 'Interesante vista a‚îú¬Ærea centrada en la gran estructura del Hogar Pignatelli y sus jardines de acceso, ubicado entre el Portillo, la calle de Ram‚îú‚îÇn Pignatelli y el paseo de Mar‚îú¬°a Agust‚îú¬°n. El central patio de ingreso y la iglesia quedan flanqueados por el patio y zona de las ni‚îú‚ñías y chicas, recayente a la calle de Vicente G‚îú‚îÇmez Salvo, y el patio y zona de los ni‚îú‚ñíos y chicos. En primer t‚îú¬Ærmino, el coso de la Misericordia, el cuartel del Cid y la Maternidad. Detr‚îú√≠s, el noviciado de Santa Ana, los modernos bloques de viviendas para funcionarios y los talleres de la DPZ. Hacia el fondo, instalaciones del Hospital provincial, la extensa zona de huerta de la Encarnaci‚îú‚îÇn y el antiguo convento. Al fondo, la Puerta del Carmen y el desemboque del arbolado bulevar del paseo de Pamplona, poco antes de ser convertido en moderna autopista. Hacia la derecha y en primer t‚îú¬Ærmino, la triangular manzana de viviendas militares entre el paseo de Mar‚îú¬°a Agust‚îú¬°n y la calle de Anselmo Clav‚îú¬Æ, Detr‚îú√≠s, el Grupo Escolar Joaqu‚îú¬°n Costa y el edificio de la Santa Hermandad del Refugio. Entre las antiguas viviendas del paseo destaca la cl‚îú¬°nica del doctor Ricardo Horno Alcorta, esquinera con la hom‚îú‚îÇnima calle, antes llamada de la Industria.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65327400, -0.89092200, '0101000020E6100000622EA9DA6E82ECBFDFA9807B9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51403815906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51403815906.webp', 'https://www.flickr.com/photos/zaragozaantigua/51403815906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23949, 'Hogar Pignatelli 1963', 'Imagen tomada en el patio del Hogar Pignatelli abierto a las residentes femeninas tras una decembrina nevada que aport‚îú‚îÇ divertidas posibilidades recreativas, adem‚îú√≠s de poder columpiarse. Cualquier nevada pasada siempre parece mejor.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65327400, -0.89092200, '0101000020E6100000622EA9DA6E82ECBFDFA9807B9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53644620881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53644620881.webp', 'https://www.flickr.com/photos/zaragozaantigua/53644620881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23990, 'Plaza de toros 1973', 'Aspecto de la plaza de toros de Zaragoza en 1973. Al fondo, torres y c‚îú‚ïëpula del Hogar Pignatelli, actual sede del Gobierno de Arag‚îú‚îÇn. Fuente: Revista El Ruedo 1.530, 1973.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18950993825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18950993825.webp', 'https://www.flickr.com/photos/zaragozaantigua/18950993825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24007, 'Plaza de Toros 1907', 'Foto: J. J‚îú‚ïëdez. Posado de las "presidentas, asesores y representantes de la Cruz Roja, en cuyo beneficio se dio la becerrada" de los cocheros, el domingo 5 de mayo de 1907, en la Plaza de Toros de Zaragoza. En primer plano, las se‚îú‚ñíoritas Sanclemente, Fuertes, de Val e Iglesias, "que ricamente ataviadas con el cl‚îú√≠sico pa‚îú‚ñíol‚îú‚îÇn de Manila y airosa mantilla blanca, ocuparon el sitio de honor, muy bien asesoradas por los distinguidos aficionados Manolo Velilla, Mariano Lorente, el veterano D. Baltasar Palomar y Julio Mart‚îú¬°n". Fuente: Revista "La fiesta nacional", Barcelona, 1907.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23912133684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23912133684.webp', 'https://www.flickr.com/photos/zaragozaantigua/23912133684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24118, 'Coso de la Misericordia 1916', 'Imagen capturada en el Coso de la Misericordia durante el mitin organizado por la Federaci‚îú‚îÇn Obrera el d‚îú¬°a 16 de marzo de 1916 para tratar el grave asunto del elevado precio de las subsistencias y la crisis del trabajo, en el contexto de la larga crisis del r‚îú¬Ægimen de la Restauraci‚îú‚îÇn mon‚îú√≠rquica agudizada en esta ocasi‚îú‚îÇn por el impacto de la Gran Guerra. Con la presidencia de Jos‚îú¬Æ Echegoyen, el acto cont‚îú‚îÇ la participaci‚îú‚îÇn de Agust‚îú¬°n Ferreruelo, Mariano Sanz y Nicol‚îú√≠s Guallarte por la Sociedad de panaderos; Santos Gaspar por la Sociedad de alba‚îú‚ñíiles y Nicasio Domingo en nombre de los carpinteros. Este mitin matinal transcurri‚îú‚îÇ bajo un sol de justicia entre las 10.30 y las 12.15 horas, con numerosas cr‚îú¬°ticas al Gobierno por la represi‚îú‚îÇn de las protestas de los obreros por el precio de las subsistencias, mientras hac‚îú¬°a la vista gorda a los acaparadores y especuladores, adem‚îú√≠s de seguir promoviendo la exportaci‚îú‚îÇn de subsistencias a la Europa en guerra. Las conclusiones del acto se le hicieron llegar al gobernador civil para que las elevase al Consejo de ministros. En primer t‚îú¬Ærmino, vista parcial de la concurrencia al mitin mirando hacia los oradores que quedaban fuera de plano y a la izquierda. Al fondo, aspecto de la plaza con las arcadas de madera originales del coso construido en el siglo XVIII, la grader‚îú¬°a de piedra del ‚îú‚ïëltimo tercio del siglo XIX y la barrera y contrabarrera colocadas unos pocos a‚îú‚ñíos antes (1908). A finales de diciembre de 1916 comenzar‚îú¬°a la gran reforma de la plaza que al finalizar los trabajos en marzo de 1918 le dar‚îú¬°a su actual aspecto neomud‚îú¬Æjar.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65457300, -0.89163000, '0101000020E6100000473D44A33B88ECBF1CEC4D0CC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52780867751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52780867751.webp', 'https://www.flickr.com/photos/zaragozaantigua/52780867751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24235, 'Coso Misericordia 1956', 'Ernest Hemingway y Mary Welsh tras la barrera del Coso de la Misericordia, "attending Bull Fight in Zaragoza", si bien Ernest est‚îú√≠ m‚îú√≠s al tanto del fot‚îú‚îÇgrafo, y bien pillo, se quita las gafas para el posado. Fuente visual: www.ernesthemingwaycollection.com/', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65453800, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFA0FEB3E6C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31839559990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31839559990.webp', 'https://www.flickr.com/photos/zaragozaantigua/31839559990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24242, 'Buffalo Bill 1950', 'Imagen capturada en el coso de la Misericordia y centrada en el personaje de Buffalo Bill, que con su espect‚îú√≠culo "Wild West Show" era cabeza de cartel del Circo Americano venido a Zaragoza con motivo de las Fiestas del Pilar e instalado con gran ‚îú¬Æxito en el Ferial de la Gran V‚îú¬°a. El actor Edward "Joe" Gray, ex capit‚îú√≠n de la Polic‚îú¬°a Montada del Canad‚îú√≠ y residente en Londres fue contratado para formar parte del circo por su "parecido" con el original Buffalo Bill/William Frederick Cody (1846-1917), aunque en alg‚îú‚ïën momento se propag‚îú‚îÇ el bulo de que era su "descendiente y heredero". La foto recoge el momento en que el personaje exhibe una de las orejas conseguidas por el diestro Luis Miguel Domingu‚îú¬°n, que se la ofreci‚îú‚îÇ tras una de sus faenas en la primera corrida de la feria del Pilar.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65457300, -0.89165200, '0101000020E61000003B376DC66988ECBF1CEC4D0CC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51706319544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51706319544.webp', 'https://www.flickr.com/photos/zaragozaantigua/51706319544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24384, 'Casa Hospicio c.1925', '"Fachada de la iglesia de la Real Casa de Misericordia". A la original y neocl‚îú√≠sica "Real Casa de la Misericordia" levantada a finales del siglo XVIII sobre las antiguas Eras del Campo del Toro, en 1867 se le a‚îú‚ñíadi‚îú‚îÇ la neobizantina iglesia, con fachada al rectangular patio de acceso desde el norte, por la calle de la Misericordia, luego de Pignatelli. Entre 1907 y 1935, este edificio fue denominado "Casa Hospicio", como espacio de beneficiencia para ni‚îú‚ñíos y ni‚îú‚ñías exp‚îú‚îÇsitas. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65327700, -0.89078800, '0101000020E61000007B6AF5D55581ECBF501DAB949ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22855791326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22855791326.webp', 'https://www.flickr.com/photos/zaragozaantigua/22855791326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25057, 'El Cordob‚îú¬Æs 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho. 30 de abril de 1965. Toros. 1‚î¨¬¨ Corrida de la Feria de Primavera. Diestros: Paco Camino, "El Cordob‚îú¬Æs" y "Serranito" Manuel Ben‚îú¬°tez es uno de los toreros m‚îú√≠s c‚îú¬Ælebres del franquismo. Aqu‚îú¬° lo vemos rodeado de admiradores en su visita a Zaragoza.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817805410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817805410.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817805410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25080, 'Gabinete Caligari 1990', 'El l‚îú¬°der del grupo musical Gabinete Caligari, Jaime Urrutia, en el concierto celebrado en la plaza de Toros de Zaragoza el 6 de mayo de 1990. Fuente: Agencia EFE.', 1990, 1990, 1990, 'Anos 90', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24601655666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24601655666.webp', 'https://www.flickr.com/photos/zaragozaantigua/24601655666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25093, 'El Baulero 1936', 'El Baulero, apodo de Pedro D‚îú¬°az Lay‚îú‚ïës (Zaragoza, 1907-1972), ten‚îú¬°a un taller de ba‚îú‚ïëles en la calle de Las Armas, y ‚îú¬Æl mismo los transportaba: en bicicleta. Hijo de torero, decidi‚îú‚îÇ probar suerte como rejoneador: en bicicleta, debutando en la plaza de Toros de Zaragoza el 18 de julio de 1936. Despu‚îú¬Æs se dedic‚îú‚îÇ a torear coches: en bicicleta. Muri‚îú‚îÇ atropellado en la calle del General Franco: caminando. Fuente: Heraldo de Arag‚îú‚îÇn.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65453400, -0.89161300, '0101000020E6100000C40776FC1788ECBF5E0F26C5C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32727769115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32727769115.webp', 'https://www.flickr.com/photos/zaragozaantigua/32727769115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25595, 'Oeste de la Romareda 1973', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Abril 1973. Imagen ligeramente en altura, desde uno de los nuevos grandes bloques de viviendas de la calle Condes de Arag‚îú‚îÇn, del panorama al oeste del nuevo Pol‚îú¬°gono Romareda, hasta el Seminario Conciliar. Junto a las nuevos y modernos viales y edificios habitacionales, conviven a‚îú‚ïën islotes verdes con campos de cultivos de herb‚îú√≠ceas y cereales. Por uno de los caminos entre esos campos estuvo trazado el recorrido del antiguo ferrocarril de Cari‚îú‚ñíena.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63914000, -0.90647300, '0101000020E6100000CF9F36AAD301EDBF60C8EA56CFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14715394467.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14715394467.webp', 'https://www.flickr.com/photos/zaragozaantigua/14715394467/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20949, 'Puerta de Santa Engracia 1828', 'Jos‚îú¬Æ Gabriel Lafuente (1828) Puerta de Santa Engracia. Tiburcio del Caso dise‚îú‚ñí‚îú‚îÇ una nueva puerta de Santa Engracia ubicada a la altura de las ruinas del convento jeronimiano de Santa Engracia y la Torre del Pino, en el vial abierto tras la guerra de 1808-1813 entre el Coso y Santa Engracia. Era una puerta en forma de arco de triunfo que recordara los Sitios, y este proyecto (porque hubo varios) se quiso acometer antes de la visita del monarca absoluto Fernando VII "El Deseado", el 22 de abril de 1828. Como no se planificaron las cosas bien, se orden‚îú‚îÇ levantar interinamente una imitaci‚îú‚îÇn de madera, lienzo y pintura denominada "Puerta Ynterina", que lo fue hasta 1830, en que se coloc‚îú‚îÇ la primera piedra...', 1828, 1828, 1828, 'Siglo XIX', 'CENTRO', 41.64957900, -0.88371200, '0101000020E6100000E8A562635E47ECBF8E95986725D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15090162539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15090162539.webp', 'https://www.flickr.com/photos/zaragozaantigua/15090162539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20951, 'Puerta de Santa Engracia 1830', '"Segunda Puerta de Santa Engracia", Antonio Callaved, 2011. Este arco conmemorativo quiso estar erguido en el actual paseo de la Independencia entre 1830 y 1866, aunque s‚îú‚îÇlo lo consigui‚îú‚îÇ siendo de madera policromada. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1830, 1830, 1830, 'Siglo XIX', 'CENTRO', 41.64944200, -0.88369000, '0101000020E6100000F3AB39403047ECBF0D535BEA20D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093334339.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093334339.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093334339/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20980, 'Paseo de Santa Engracia 1833', '"Dibujo que representa las fachadas de los edificios que deben executar los que hayan de reedificar sus casas en la distancia que media entre la plaza de San Fernando y la Puerta de Santa Engracia que se est‚îú√≠ construyendo", 1833. Dibujo que contiene tres figuras: dos alzados correspondientes a las esquinas con la plaza de San Fernando (hoy de Espa‚îú‚ñía) y la Puerta de Santa Engracia (hoy plaza de Arag‚îú‚îÇn), y una planta de los mismos emplazamientos. Este paseo se llamar‚îú√≠ de Santa Engracia, luego Sal‚îú‚îÇn de Pignatelli y hoy de la Independencia. Fuente: AMZ.', 1833, 1833, 1833, 'Siglo XIX', 'CENTRO', 41.65056200, -0.88277000, '0101000020E61000003A7AFCDEA63FECBF9B02999D45D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20870392918.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20870392918.webp', 'https://www.flickr.com/photos/zaragozaantigua/20870392918/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21037, 'Cabalgata 1860', 'Dibujo ilustrativo de la cabalgata que en octubre de 1860 recre‚îú‚îÇ de forma libre la coronaci‚îú‚îÇn de Fernando de Antequera como rey de Arag‚îú‚îÇn tras el Compromiso de Caspe de 1412. Este evento estuvo incluido en el programa de actos organizado con motivo de la visita a la ciudad de la reina Isabel II, el rey consorte Francisco de As‚îú¬°s, los infantes y el heredero al trono, futuro Alfonso XII. Enanos y Gigantones, adem‚îú√≠s de carros aleg‚îú‚îÇricos decorados con diversos motivos acompa‚îú‚ñíaron a la cabalgata en su recorrido desde la Real Casa de Misericordia hasta el Palacio Arzobispal en funciones de Palacio Real, incluyendo algunos giros hasta la plaza de la Magdalena y la del Mercado, para regresar finalmente al lugar de salida. En el dibujo, la recreacionista cabalgata avanza por el Sal‚îú‚îÇn de Pignatelli, decorado con vegetales arcos y banderolas al viento. Fuente visual: revista El Museo Universal (Madrid, 25/11/1860).', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64974900, -0.88322800, '0101000020E6100000E92ADD5D6743ECBFEACDA8F92AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35609880824.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35609880824.webp', 'https://www.flickr.com/photos/zaragozaantigua/35609880824/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21134, 'Calle de la Independencia c.1880', 'Imagen coloreada con una ins‚îú‚îÇlita y simp‚îú√≠tica vista del ‚îú‚ïëltimo tramo de los n‚îú‚ïëmeros pares de la calle de la Independencia, centrada en el solar ocupado en el centro de la escena por los Ba‚îú‚ñíos de Ferm‚îú¬°n Zacar‚îú¬°as ‚îú√¨‚îú‚ñíigo, en cuya esquina recayente con la calle del Azoque (tramo luego redenominado del Marqu‚îú¬Æs de Casa Jim‚îú¬Ænez) y desde 1864 estaba ubicado el Teatro de Novedades, clausurado en 1892 para dar paso a los inmuebles que poco despu‚îú¬Æs se construir‚îú¬°an all‚îú¬° y completar‚îú¬°an la visual de los porches a la parisina forma que singularizan este espacio. A la izquierda, el original inmueble conocido como Ambos Mundos por albergar ese hom‚îú‚îÇnimo y prestigioso gran caf‚îú¬Æ. Al fondo, la plaza de la Constituci‚îú‚îÇn', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.64973900, -0.88374400, '0101000020E6100000BF28417FA147ECBFC6F7C5A52AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49896759551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49896759551.webp', 'https://www.flickr.com/photos/zaragozaantigua/49896759551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21204, 'Caf‚îú¬Æ Ambos Mundos c.1890', 'Imagen del interior del caf‚îú¬Æ Ambos Mundos con el aspecto conferido por la reforma que en 1889 y con proyecto del arquitecto Julio Bravo le dio este apabullante aspecto decorativo en "estilo renacimiento".', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64939400, -0.88427000, '0101000020E610000079AF5A99F04BECBFFC1BB4571FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54394831882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54394831882.webp', 'https://www.flickr.com/photos/zaragozaantigua/54394831882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21307, 'Calle de la Independencia c.1906', 'Festiva imagen capturada en el andador central de la calle de la Independencia, mientras la comparsa de cabezudos encorre a la chiquiller‚îú¬°a en direcci‚îú‚îÇn a la plaza de la Constituci‚îú‚îÇn, a la altura de los antiguos n‚îú‚ïëmeros del 15, 17 y 19, este ‚îú‚ïëltimo correspondiente con el convento de las Religiosas de Jerusal‚îú¬Æn, a la derecha. Centra la escena el cabezudo que representa al Tuerto metido en faena. Fuente visual: imagen estereosc‚îú‚îÇpica reproducida en El Peri‚îú‚îÇdico de Arag‚îú‚îÇn. En GAZA ofrecemos una composici‚îú‚îÇn basada en ella.', 1906, 1906, 1906, 'Anos 1900', 'CENTRO', 41.65083600, -0.88196400, '0101000020E6100000A0FA07910C39ECBF9C8713984ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34975554010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34975554010.webp', 'https://www.flickr.com/photos/zaragozaantigua/34975554010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21365, 'P.‚î¨‚ïë de la Independencia 1913', 'Acto castrense en el paseo: "Jura de banderas", el 13 de abril de 1913. A la derecha, el palacete del bar‚îú‚îÇn de la Rosa (n‚î¨‚ïë 29), que fuera sede de la Capitan‚îú¬°a General entre 1867 y 1888, y casa de Luis Bu‚îú‚ñíuel entre 1906 y 1917, antes de ser derribado en 1927 para levantar el nuevo edificio del Heraldo de Arag‚îú‚îÇn, y el de Escoriaza. Al otro lado de la plaza de Santa Engracia, los porches del paseo ya terminados, con p‚îú‚ïëblico encaramado, pero sin el edificio de Correos.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64970500, -0.88318000, '0101000020E6100000A5660FB40243ECBF1A868F8829D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14920637137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14920637137.webp', 'https://www.flickr.com/photos/zaragozaantigua/14920637137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21390, 'P.‚î¨‚ïë de la Independencia 1913', 'Paseo de la Independencia de Zaragoza el 19 de marzo de 1913, con visual de los edificios de la acera de los impares. Junto a la plaza de Santa Engracia, el palacio del conde de la Rosa. Al fondo, el quiosco de la m‚îú‚ïësica. Foto: Lorenzo Almarza. Fuente visual: Archivo de la Diputaci‚îú‚îÇn Provincial de Huesca www.dphuesca.es/', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20742624271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20742624271.webp', 'https://www.flickr.com/photos/zaragozaantigua/20742624271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21396, 'P.‚î¨‚ïë de la Independencia 1913', 'Foto: Lorenzo Almarza. "Jura de banderas. El beso". Fotograf‚îú¬°a de detalle del paseo de la Independencia de Zaragoza el 13 de abril de 1913, con un quiosco en primer plano y vista parcial del teatro Pignatelli, que ser‚îú√≠ cerrado tras las fiestas del Pilar de 1914. En parte de su solar se inaugurar‚îú√≠ el edificio de Correos en 1926. Fuente visual: Archivo Diputaci‚îú‚îÇn Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64947300, -0.88373500, '0101000020E6100000F3936A9F8E47ECBF485167EE21D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21469490155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21469490155.webp', 'https://www.flickr.com/photos/zaragozaantigua/21469490155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21398, 'P.‚î¨‚ïë de la Independencia 1913', 'Foto: Lorenzo Almarza. Desfile militar en el paseo de la Independencia de Zaragoza en 1913. Al fondo, una torreta de la Facultad de Medicina y Ciencias. Hemos volteado horizontalmente la imagen para darle sentido. Fuente: Archivo de la Diputaci‚îú‚îÇn Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21471724675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21471724675.webp', 'https://www.flickr.com/photos/zaragozaantigua/21471724675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21424, 'Calle de la Independencia 1911', 'Esta captura es titulada "Jura de bandera de los artilleros en la plaza Arag‚îú‚îÇn de Zaragoza", aunque nos parece que dicha plaza queda m‚îú√≠s al sur (hacia la derecha de la imagen), y el evento est‚îú√≠ sucediendo en el andador central de la calle de la Independencia, a la altura del emboque a la de Felipe Sanclemente, que contin‚îú‚ïëa hacia el fondo, y nos ofrece una ins‚îú‚îÇlita visual del n‚î¨‚ïë 2 de esa calle. En primer plano, vista parcial del n‚î¨‚ïë 25 de Independencia, en cuyos bajos se ubicaba el Caf‚îú¬Æ de la Iberia, y del esquinero n‚î¨‚ïë 27, ambos de alturas bastante provincianas. Confronta, al otro lado de la calle, el entra‚îú‚ñíable edificio-manzana (peque‚îú‚ñía) delimitado por las calles de Felipe Sanclemente, Santa Engracia, Garc‚îú¬°a Gil, y la propia de Independencia. Fuente visual: Luis Gand‚îú‚ïë Mercadal, patrimoniocultural.unizar.es/', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65002300, -0.88296300, '0101000020E61000005F7F129F3B41ECBFEB5223F433D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32206536506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32206536506.webp', 'https://www.flickr.com/photos/zaragozaantigua/32206536506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21435, 'Teatro Circo 1911', 'Foto: Grasa. Posado del personal sanitario del hospital de sangre instalado en el caf‚îú¬Æ del Teatro Circo de la calle de San Miguel, durante la huelga general revolucionaria del verano-oto‚îú‚ñío de 1911. Fuente: Diario ABC, 22-9-1911.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65079900, -0.88038500, '0101000020E61000005C72DC291D2CECBF7FA2B2614DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40166094270.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40166094270.webp', 'https://www.flickr.com/photos/zaragozaantigua/40166094270/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21440, 'P.‚î¨‚ïë de la Independencia 1913', 'Luminosa imagen capturada en el paseo de la Independencia y centrada en la ubicaci‚îú‚îÇn del bulevar central donde poco antes (1912) hab‚îú¬°a sido instalado el Quiosco de la M‚îú‚ïësica, ideado originalmente por los hermanos Mart‚îú¬°nez Ubago para la Exposici‚îú‚îÇn Hispano Francesa de 1908. Aqu‚îú¬° estar‚îú¬°a hasta que en 1927 fue recolocado en el antiguo recinto expositivo, ya urbanizado como plaza de Castelar. Al fondo y a la izquierda, la calle de Jer‚îú‚îÇnimo Zurita, y a continuaci‚îú‚îÇn el antiguo inmueble de los n‚îú‚ïëmeros 23-25 del paseo. En los bajos del n‚î¨‚ïë 25, a la derecha, destaca el ingreso al Caf‚îú¬Æ de la Iberia en su segunda ‚îú¬Æpoca (desde 1893), considerado en su momento el segundo caf‚îú¬Æ en tama‚îú‚ñío de Zaragoza, tras el Ambos Mundos. Al inicio de la d‚îú¬Æcada de los a‚îú‚ñíos 30 aqu‚îú¬° se ubicar‚îú¬°a el moderno Caf‚îú¬Æ-Cervecer‚îú¬°a Baviera.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65037200, -0.88271400, '0101000020E61000004015376E313FECBFF71DC3633FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48568827556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48568827556.webp', 'https://www.flickr.com/photos/zaragozaantigua/48568827556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21443, 'P.‚î¨‚ïë de la Independencia c.1918', 'Imagen capturada en el andador central del paseo de la Independencia durante una fresca ma‚îú‚ñíana y centrada en el Quiosco de la M‚îú‚ïësica donde una orquesta toca m‚îú‚ïësica, rodeado de numeroso p‚îú‚ïëblico. Por el paseo arriba, endomingadas se‚îú‚ñíoras y se‚îú‚ñíores, y algunas amas de cr‚îú¬°a. A la izquierda, la calle de Fray Diego Murillo se abre entre los inmuebles de los n‚îú‚ïëmeros 14 y 16 del paseo, de los se‚îú‚ñíores Jos‚îú¬Æ Moncasi y Santiago Baselga, respectivamente. Al fondo, leve vista de la emergente torre de Nuestra Se‚îú‚ñíora del Pilar del hom‚îú‚îÇnimo templo.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65055700, -0.88262900, '0101000020E6100000B309302C7F3EECBF8997A77345D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49847053757.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49847053757.webp', 'https://www.flickr.com/photos/zaragozaantigua/49847053757/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21474, 'Cinema Alhambra 1911', 'Ubicado en el paseo de la Independencia 26, el Cinema Alhambra se inaugur‚îú‚îÇ el 6 de octubre de 1911. Construido seg‚îú‚ïën dise‚îú‚ñío del arquitecto F‚îú¬Ælix Navarro, la obra fue terminada por su hijo Miguel ‚îú√ºngel Navarro. Su decoraci‚îú‚îÇn interior era neonazar‚îú¬°. Fue clausurado en agosto de 1965. En su solar se levant‚îú‚îÇ el Cine Avenida en 1967.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65019900, -0.88332600, '0101000020E61000009D9B36E33444ECBF2A7288B839D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54394485322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54394485322.webp', 'https://www.flickr.com/photos/zaragozaantigua/54394485322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21483, 'P.‚î¨‚ïë de la Independencia c.1926', 'El edificio situado en el paseo de la Independencia 29, conocido como Casa Pamplona, que hab‚îú¬°a sido Capitan‚îú¬°a General, estuvo ocupado en parte por los Hermanos Corazonistas entre 1904 y 1910. Luis Bu‚îú‚ñíuel vivi‚îú‚îÇ en este mismo edificio entre 1906 y 1917. Desde 1931, los n‚îú‚ïëmeros 29 y 31 del paseo los ocupan el Heraldo de Arag‚îú‚îÇn y la casa de la familia Escoriaza, codo con codo y demolida ya la casa que nos ocupa. Al fondo, los nuevos edificios de Correos y tel‚îú¬Ægrafos y el m‚îú√≠s nuevo y en obras de los tel‚îú¬Æfonos. Fuente: Luis Bu‚îú‚ñíuel. La forja de un cineasta universal, 2013.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64962500, -0.88312300, '0101000020E6100000950D6B2A8B42ECBFFED478E926D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14962269776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14962269776.webp', 'https://www.flickr.com/photos/zaragozaantigua/14962269776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22309, 'Tony Leblanc 1965', 'Visita a Zaragoza, acompa‚îú‚ñíando a la cantante folcl‚îú‚îÇrica Lolita Sevilla, del humorista madrile‚îú‚ñío Tony Leblanc (1922-2012) (en el centro, en un sal‚îú‚îÇn de la Residencia Sanitaria Jos‚îú¬Æ Antonio o Casa Grande). Nacido en el Museo del Prado de Madrid como Ignacio Fern‚îú√≠ndez, particip‚îú‚îÇ en pel‚îú¬°culas populares desplegando su indudable vis c‚îú‚îÇmica. El momento cumbre de su carrera fue cuando se comi‚îú‚îÇ una manzana en directo en Televisi‚îú‚îÇn Espa‚îú‚ñíola, en 1977. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63537800, -0.90032100, '0101000020E610000051DD5CFC6DCFECBF884CF91054D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15661700347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15661700347.webp', 'https://www.flickr.com/photos/zaragozaantigua/15661700347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21519, 'Casa Jim‚îú¬Ænez 1921', 'Una fotograf‚îú¬°a casual de Rufina, en tono familiar, sin m‚îú√≠s pretensiones que captar un instante relajado y dom‚îú¬Æstico, con el inopinado fondo urbano del momento. El resultado es espectacular. El marco esc‚îú¬Ænico es la calle de Casa Jim‚îú¬Ænez en su ligaz‚îú‚îÇn con el tranquilo paseo de la Independencia. Al otro lado, la portada de la parroquia de Santa Engracia (remozada 30 a‚îú‚ñíos antes por Mariano L‚îú‚îÇpez), en una visual ins‚îú‚îÇlita, pues el edificio de "Correos y Tel‚îú¬Ægrafos" no est‚îú√≠, y apenas si despuntan los arquitrabados neo-porches que delimitan una parte del espacio que hasta hac‚îú¬°a unos pocos a‚îú‚ñíos ocupaba el fungible Teatro Pignatelli. Ni siquiera el alto edificio de la derecha es el mismo: unos a‚îú‚ñíos despu‚îú¬Æs, Pascual Bravo reformar‚îú¬°a profundamente este enorme recept‚îú√≠culo, en sus bajos, del se‚îú‚ñíalado y desaparecido caf‚îú¬Æ "Ambos Mundos". Fuente visual: fotograf‚îú¬°a de Julio Requejo, proporcionada amablemente por Mariano Lacruz.', 1921, 1921, 1921, 'Anos 20', 'CENTRO', 41.64988300, -0.88417400, '0101000020E6100000F226BF45274BECBFFA9CBB5D2FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16461101982.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16461101982.webp', 'https://www.flickr.com/photos/zaragozaantigua/16461101982/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21522, 'Calle de C‚îú√≠diz 1923', 'Desde las traseras de su casa de la calle Casa Jim‚îú¬Ænez, el fot‚îú‚îÇgrafo Julio Requejo captur‚îú‚îÇ esta imagen que titul‚îú‚îÇ muy apropiadamente "El Pilar desde casa", pues al fondo se perfilan sus dos torres y el gran cupul‚îú‚îÇn central, y si sale el Pilar, nada m‚îú√≠s les importa. Por eso, incrustamos un anglosaj‚îú‚îÇn "off-topic" para derivar la visual hacia el espacio urbano, el "aire", que fluye hasta la calle C‚îú√≠diz, pues su tramo entre Laurel y San Diego presenta una in‚îú¬Ædita visi‚îú‚îÇn de las traseras del antiguo Colegio de las Hermanas Recogidas, con el arranque del edificio que alberga su iglesia justo a la izquierda. Este colegio fue fundado en 1594 como "casa para el recogimiento de mujeres perdidas y escandalosas", pues supon‚îú¬°an una amenaza mucho grande para el orden p‚îú‚ïëblico y la moral de la Monarqu‚îú¬°a Hisp‚îú√≠nica, imperial, contrarreformista y ultracat‚îú‚îÇlica. Al menos, en Zaragoza. Tras deambular por diversas ubicaciones, el Virrey Conde de Lemos posibilit‚îú‚îÇ en 1647 su establecimiento aqu‚îú¬°, en la antigua Morer‚îú¬°a, aunque ya sin moros en ella, pues hab‚îú¬°an sido expulsados en 1610. Con el tiempo, este edificio dej‚îú‚îÇ de tener sentido, y desde 1815 funcion‚îú‚îÇ como m‚îú√≠s rentable colegio de ni‚îú‚ñías, llevado por monjas carmelitas de la Tercera Orden, aunque la impronta conventual lleg‚îú‚îÇ a dar nombre a la calle "de las Recogidas", que tras pasar un riego continuaba como "de Veruela", y llegaba hasta el nov‚îú¬°simo "Sal‚îú‚îÇn de Santa Engracia". Al comienzo de la d‚îú¬Æcada de los 70 del pasado siglo XX el colegio era llevado por Carmelitas Misioneras Teresianas, que en 1977 lo vendieron para sacar unas perrillas con que pagarse unas nuevas y lejanas instalaciones en el barrio de Casablanca. En el plazo de un a‚îú‚ñío, fue piqueteado (incluyendo la neocl‚îú√≠sica iglesia de su interior), para levantar en su solar una pionera y muy necesaria gran superficie comercial. Fuente visual: AHPZ, Archivo Julio Requejo.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65090100, -0.88405600, '0101000020E610000076A4FACE2F4AECBF83F755B950D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16784806103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16784806103.webp', 'https://www.flickr.com/photos/zaragozaantigua/16784806103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21523, 'P.‚î¨‚ïë de la Independencia 1926', 'Imagen tomada desde la azotea del nuevo edificio de la Central Telef‚îú‚îÇnica, en el paseo de la Independencia, en un atardecer ya cercano a la noche. A los pies, inmediato, el nuevo edificio de Correos, con sus remates neomud‚îú¬Æjares. Al otro lado de la plaza de Santa Engracia, el palacete del bar‚îú‚îÇn de la Rosa, que fuera sede de la Capitan‚îú¬°a General entre 1867 y 1888, y casa de Luis Bu‚îú‚ñíuel entre 1906 y 1917, muy poco antes de ser derribado. Al otro lado del paseo, perspectiva "ruedurivoliense" muy parisina, irrepetible, como el arbolado paseo central, con la farolas reci‚îú¬Æn encendidas. Al fondo, brilla la plaza de la Constituci‚îú‚îÇn, y el tel‚îú‚îÇn de fondo de la torre de San Felipe, la c‚îú‚ïëpula y torres de Sta. Isabel, El Pilar, un par de palomares, la azucarera del Arrabal, San Gil, la torre y cimborrio de la Seo, y la c‚îú‚ïëpula de la central de una entidad de ahorro. Fuente visual: Fundaci‚îú‚îÇn Telef‚îú‚îÇnica', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16834144590.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16834144590.webp', 'https://www.flickr.com/photos/zaragozaantigua/16834144590/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21559, 'Arco triunfal 1927', 'En su calidad de arquitecto municipal, Miguel ‚îú√ºngel Navarro repiti‚îú‚îÇ experiencia en materia de celebraci‚îú‚îÇn de triunfos militares durante la dictadura de Primo de Rivera, y dos a‚îú‚ñíos despu‚îú¬Æs dise‚îú‚ñí‚îú‚îÇ otro "arco triunfal" costeado por el Ayuntamiento, esta vez con ocasi‚îú‚îÇn del "homenaje de la victoria y de la fiesta de la raza", en el marco de la colonial "Guerra del Rif" en Marruecos. El desfile fue tambi‚îú¬Æn el 12 de octubre, repitiendo localizaci‚îú‚îÇn en el paseo de la Independencia, a medio camino entre la plaza de Arag‚îú‚îÇn, y la de la Constituci‚îú‚îÇn. Esta vez el dise‚îú‚ñío fue en "estilo ‚îú√≠rabe" (sic), si bien adobado con la ense‚îú‚ñía nacional espa‚îú‚ñíola, los escudos de Espa‚îú‚ñía y de Zaragoza, emblemas de todas las armas del ej‚îú¬Ærcito, e inscripciones alusivas a las localidades marroqu‚îú¬°es de Xauen y Alhucemas. Sobre el arco central, la leyenda "A sus h‚îú¬Æroes, la patria agradecida", en una cara, y "La ciudad inmortal a sus soldados", en la otra. En la imagen, el ef‚îú¬°mero arco con el lejano fondo de la plaza de Arag‚îú‚îÇn y el monumento al Justiciazgo. Fuente visual: Juan Mora Insa, DARA-AHPZ.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65056200, -0.88277000, '0101000020E61000003A7AFCDEA63FECBF9B02999D45D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22258876329.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22258876329.webp', 'https://www.flickr.com/photos/zaragozaantigua/22258876329/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21576, 'P.‚î¨‚ïë de la Independencia c.1920', 'Paseo de la Independencia. Al fondo, el Quiosco de la M‚îú‚ïësica. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65028300, -0.88272600, '0101000020E61000005186AA984A3FECBF88122D793CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24269505103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24269505103.webp', 'https://www.flickr.com/photos/zaragozaantigua/24269505103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21584, 'P.‚î¨‚ïë de la Independencia 1927', 'Imagen de la denominada "Fiesta de la Paz" celebrada el doce de octubre de ese a‚îú‚ñío, con el desfile de tropas de guarnici‚îú‚îÇn de la ciudad, y de repatriados de las campa‚îú‚ñías de Marruecos, bajo el ef‚îú¬°mero arco triunfal dise‚îú‚ñíado para la ocasi‚îú‚îÇn. El desfile por el arbolado paseo, con veh‚îú¬°culos a propulsi‚îú‚îÇn de sangre, va camino de la plaza de Arag‚îú‚îÇn, que queda al fondo. Fuente visual: Miguel Mar‚îú¬°n Chivite, para ABC.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.65056200, -0.88277000, '0101000020E61000003A7AFCDEA63FECBF9B02999D45D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24604563470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24604563470.webp', 'https://www.flickr.com/photos/zaragozaantigua/24604563470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21604, 'Teatro Variedades 1922', 'Fachada del Teatro Variedades, inaugurado en 1899 en el paseo de la Independencia 24. Es considerado el primer cine estable de la ciudad. En 1934 fue sustituido por el Cine Actualidades, cerrado en 1979. En la imagen, el teatro anuncia el decimon‚îú‚îÇnico texto de Antonio Gil de Z‚îú√≠rate "Carlos II el Hechizado, drama en tres actos", representado por el cuadro c‚îú‚îÇmico-dram‚îú√≠tico de Emilio Portes, con direcci‚îú‚îÇn de Nicanor Puga.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.65038700, -0.88312300, '0101000020E6100000950D6B2A8B42ECBF2D5F97E13FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27370164186.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27370164186.webp', 'https://www.flickr.com/photos/zaragozaantigua/27370164186/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21811, 'P.‚î¨‚ïë de la Independencia 1930', 'La librer‚îú¬°a Fernando F‚îú¬Æ de Madrid, sita en el n‚îú‚ïëmero 15 de la Puerta del Sol, fue fundada en 1840 y era la m‚îú√≠s c‚îú¬Ælebre de la capital. Tras su venta en 1928, se convirti‚îú‚îÇ en la casa central del servicio de librer‚îú¬°a de la Compa‚îú‚ñí‚îú¬°a ‚îú√¨bero Americana de Publicaciones (CIAP). Esta editorial ten‚îú¬°a librer‚îú¬°as propias repartidas por toda Espa‚îú‚ñía, como la que abri‚îú‚îÇ en 1930 en el paseo de la Independencia 23 y 25 de Zaragoza. La CIAP quebr‚îú‚îÇ en 1931. En la imagen para postal publicitaria, la ef‚îú¬°mera "Librer‚îú¬°a F‚îú¬Æ", en la esquina con la calle de Jer‚îú‚îÇnimo Zurita (izquierda). Fuente visual: www.todocoleccion.net', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65037700, -0.88245900, '0101000020E610000099F221A81A3DECBF0989B48D3FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29974878344.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29974878344.webp', 'https://www.flickr.com/photos/zaragozaantigua/29974878344/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21855, 'Calle de San Miguel 1934', 'Nebulosa e ins‚îú‚îÇlita imagen de la calle de San Miguel capturada a la altura del antiguo n‚îú‚ïëmero 12 y orientada en direcci‚îú‚îÇn a su inicio, al fondo, desde el paseo de la Independencia. A la derecha e inmeditado, el edificio de la central el‚îú¬Æctrica recayente a las calles de Blancas (la calle que desemboca en primer t‚îú¬Ærmino) y de Porcell. A la izquierda, la fachada del Teatro Circo, esquinero con la calle de Isaac Peral. Al fondo, a la derecha, cartel anunciador del moderno Cine Goya, que confronta con la sede central de ERZ. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65084700, -0.88004200, '0101000020E6100000E46723D74D29ECBF90D959F44ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36065570950.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36065570950.webp', 'https://www.flickr.com/photos/zaragozaantigua/36065570950/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21858, 'Calle de Joaqu‚îú¬°n Costa 1931', 'Imagen capturada desde cierta altura y centrada en el arranque de la calle de Joaqu‚îú¬°n Costa, donde destaca, a punto de ser terminado, el moderno edificio de la Caja de Previsi‚îú‚îÇn Social de Arag‚îú‚îÇn dise‚îú‚ñíado por Regino Borobio, cuyo tama‚îú‚ñío entonces era adjetivado como "gigantesco". Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64930800, -0.88262700, '0101000020E6100000862172FA7A3EECBFFD8348861CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36126383750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36126383750.webp', 'https://www.flickr.com/photos/zaragozaantigua/36126383750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25597, 'Pol‚îú¬°gono Romareda 1972', 'Mientras se ultimaban los trabajos de urbanizaci‚îú‚îÇn del nov‚îú¬°simo Pol‚îú¬°gono Romareda, y que construyeran el minibloque del Restaurante "Rogelios", que ahora impide ver igual que en la imagen la iglesia de Santa M‚îú‚îÇnica, las traseras del municipal estadio de f‚îú‚ïëtbol (calle Eduardo Ibarra) fueron provisional lugar de pr‚îú√≠cticas de una autoescuela para aspirantes al carnet de conducir coches... y tractores. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.63650200, -0.90367900, '0101000020E61000009D9FE238F0EAECBF57EBC4E578D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850487712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850487712.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850487712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21933, 'Caja de Previsi‚îú‚îÇn Social 1946', 'AHPZ. Archivo Coyne, 1946. "Edificio de la Caja de Previsi‚îú‚îÇn Social de Arag‚îú‚îÇn". Si hasta 1900 la presencia de las Cajas de Ahorro se limit‚îú‚îÇ a la Caja de Ahorros y Monte de Piedad de Zaragoza (1876), en los a‚îú‚ñíos siguientes se constituyeron otras: la Caja Obrera de Ahorros y Pr‚îú¬Æstamos de la Inmaculada Concepci‚îú‚îÇn (CAI), en 1905, impulsada por la Acci‚îú‚îÇn Social Cat‚îú‚îÇlica vinculada al Arzobispado; la Asociaci‚îú‚îÇn de Labradores de Zaragoza (ALZ) cre‚îú‚îÇ en 1915 su Caja de Ahorros (transformada en Banco Agrario de Arag‚îú‚îÇn en 1947); y el sindicalismo agrario cat‚îú‚îÇlico (Sindicato Central de Arag‚îú‚îÇn de Asociaciones Agr‚îú¬°colas Cat‚îú‚îÇlicas) promovi‚îú‚îÇ en 1918 su propia Caja de Ahorros. En este contexto, el Instituto de Previsi‚îú‚îÇn Social creado en 1921 constituy‚îú‚îÇ su propia Caja, que en lo a‚îú‚ñíos treinta lleg‚îú‚îÇ a contar con una red de 21 delegaciones y agencias. En la imagen, el edificio central de esta Caja, de 1931 seg‚îú‚ïën dise‚îú‚ñío de Regino y Jos‚îú¬Æ Borobio en la calle Costa, n‚î¨‚ïë 1, popularmente denominado "Casa de la Perra Gorda" y actual sede de UGT.', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.64939400, -0.88260700, '0101000020E6100000BF0F0709513EECBFFC1BB4571FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15030497922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15030497922.webp', 'https://www.flickr.com/photos/zaragozaantigua/15030497922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22002, 'Cine Dorado 1949', '"Proyecto de reforma del Cine Dorado. Perspectiva". Arquitecto Santiago Lagunas y pintores Ferm‚îú¬°n Aguayo y Eloy Laguardia. El antiguo edificio del cine Dor‚îú¬Æ en el paseo de la Independencia 14 (Teodoro R‚îú¬°os, 1914) permaneci‚îú‚îÇ asi entre 1949 y 1967, cuando fue de nuevo reformado. Los tres artistas responsables formaban el Grupo P‚îú‚îÇrtico. Fuente: www.enciclopedia-aragonesa.com', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65065000, -0.88289900, '0101000020E6100000AF795567B540ECBF3A92CB7F48D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33782848686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33782848686.webp', 'https://www.flickr.com/photos/zaragozaantigua/33782848686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22061, 'P.‚î¨‚ïë de la Independencia 1955', 'Archivo Heraldo de Arag‚îú‚îÇn. Gerardo Sancho. 1955. Imagen de arbolado andador central del antiguo paseo de la Independencia. Tras su desmontaje, las farolas de este andador fueron reubicadas unos a‚îú‚ñíos despu‚îú¬Æs en el Parque Pignatelli. Los ‚îú√≠rboles, no.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65044400, -0.88279000, '0101000020E6100000008C67D0D03FECBF91F0BDBF41D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15009124135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15009124135.webp', 'https://www.flickr.com/photos/zaragozaantigua/15009124135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22195, 'Tranv‚îú¬°a a‚îú‚ñíos 50', 'Una unidad tranviaria pasa por el paseo de la Independencia, con la plaza de Santa Engracia al fondo. Fuente: Heraldo de Arag‚îú‚îÇn.', 1950, 1950, 1959, 'Anos 50', 'CENTRO', 41.64958300, -0.88358600, '0101000020E6100000B682A6255646ECBFCF84268925D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32846598080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32846598080.webp', 'https://www.flickr.com/photos/zaragozaantigua/32846598080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22331, 'Paseo Independencia 1965', 'Foto Pomar‚îú‚îÇn, 1965. Imagen de la acera de los impares del paseo de la Independencia de Zaragoza en 1965, desde la plaza de Espa‚îú‚ñía hasta el n‚îú‚ïëmero 29.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18652828506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18652828506.webp', 'https://www.flickr.com/photos/zaragozaantigua/18652828506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22354, 'Paseo Independencia c.1962', 'Foto: Colecci‚îú‚îÇn Sanz San Emeterio. Vista de los edificios de la acera de los pares del paseo de la Independencia de Zaragoza, con la plaza de Espa‚îú‚ñía al fondo. Fuente: rafaelcastillejo.com', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65089300, -0.88241400, '0101000020E61000009A0AF148BC3CECBF01193A7650D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20681011796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20681011796.webp', 'https://www.flickr.com/photos/zaragozaantigua/20681011796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22374, 'Vista a‚îú¬Ærea paseo Independencia 1965', 'Vista a‚îú¬Ærea con el paseo de la Independencia en el centro. Al fondo, el norte de la ciudad. Fuente visual : Fotograf‚îú¬°a a‚îú¬Ærea Lecar para el libro "El Ayuntamiento de Zaragoza", Colecci‚îú‚îÇn Rafael Margal‚îú¬Æ.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64948100, -0.88383100, '0101000020E61000007A1C06F35748ECBFCB2F833122D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22128978758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22128978758.webp', 'https://www.flickr.com/photos/zaragozaantigua/22128978758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22401, 'Cine Coliseo 1961', 'Aspecto del estreno de la pel‚îú¬°cula Ben-Hur en el cine Coliseo Equitativa, el 3 de enero de 1961. Esta sala, construida en 1949 seg‚îú‚ïën proyecto de Jos‚îú¬Æ de Yarza y Manuel Mart‚îú¬°nez, se encontraba en el paseo de la Independencia 19. A la izquierda, bloques de casas a‚îú‚ïën sin derribar para construir unos grandes almacenes continuando los porches hacia la plaza de Espa‚îú‚ñía. A la derecha, sala de fiestas Capri. Fuente: www.rafaelcastillejo.com', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.65083600, -0.88196400, '0101000020E6100000A0FA07910C39ECBF9C8713984ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23583675576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23583675576.webp', 'https://www.flickr.com/photos/zaragozaantigua/23583675576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22406, 'Paseo de la Independencia 1968', 'Imagen de los pilares que sustentan los porches del paseo de la Independencia, como cartelera anunciante del cine que se proyectaba en la ciudad, en esos antiguos y provincianos establecimientos cinematogr‚îú√≠ficos, a los que se pod‚îú¬°a ir andando, qu‚îú¬Æ atraso, luego felizmente sustituidos por otras cosas m‚îú√≠s modernas, y a varios kil‚îú‚îÇmetros de la ciudad. Un "botones" ha sido impactado por el cartel de uno de los filmes publicitados en el paseo, cuando la traducci‚îú‚îÇn de los t‚îú¬°tulos (adem‚îú√≠s del doblaje obligatorio, por Orden Ministerial de 1941) era una implacable y castiza moda impuesta. As‚îú¬°, la g‚îú‚îÇtica "The Black Torment" fue transustanciada en "Horror en la mansi‚îú‚îÇn Fordyke", y en el caso de la pel‚îú¬°cula de Arthur Penn, "Bonnie & Clyde" se qued‚îú‚îÇ en el cacof‚îú‚îÇnico "Bonnie y Clyde", que clarifica significativamente el t‚îú¬°tulo. Era una de las cosas buenas de aquellos tiempos: todo el mundo hablaba espa‚îú‚ñíol, aunque en ocasiones resultara m‚îú√≠s de Churubusco, que de Valladolid. Mas quienes tuvieron que desplazarse, por vocaci‚îú‚îÇn, o necesidad, pronto descubrieron, all‚îú√≠ afuera, una realidad m‚îú√≠s plural y compleja. Qu‚îú¬Æ recuerdos. Fuente: "Zaragoza Viva" (1969).', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65077200, -0.88269400, '0101000020E61000007903CC7C073FECBF8693347F4CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24476390801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24476390801.webp', 'https://www.flickr.com/photos/zaragozaantigua/24476390801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22445, 'Cineastas 1965', 'Interesante orla de la "primera promoci‚îú‚îÇn de la Escuela Cesaraugustana de directores cinematogr‚îú√≠ficos, 1965". Como decano figura el excelent‚îú¬°simo Luis Bu‚îú‚ñíuel, flanqueado por los catedr‚îú√≠ticos Sergu‚îú¬Æi Eisenstein y Charles Chaplin, adem‚îú√≠s de una interesante n‚îú‚îÇmina de cualificados profesores europeos y norteamericanos del ramo audiovisual. Los alumnos de esta hornada conforman un excelente muestrario del cine independiente y amateur que, con toda la dignidad del mundo, se pod‚îú¬°a llegar a hacer en la ciudad en esos a‚îú‚ñíos. Entre ellos se encuentra Jos‚îú¬Æ Luis Pomar‚îú‚îÇn, en cuyo estudio profesional del paseo de la Independencia n‚î¨‚ïë 30 se realiz‚îú‚îÇ esta iluminada obra. Fuente: www.todocoleccion.net/', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64984500, -0.88379700, '0101000020E610000075B169A51048ECBF0C3CF71E2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30985898885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30985898885.webp', 'https://www.flickr.com/photos/zaragozaantigua/30985898885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22537, 'Paseo Independencia 1972', 'Un tranv‚îú¬°a de la l‚îú¬°nea 11 parque-San Jos‚îú¬Æ atraviesa el paseo de la Independencia. Tambi‚îú¬Æn aparece un caracter‚îú¬°stico taxi de la ‚îú¬Æpoca. Al fondo, la plaza de Espa‚îú‚ñía. Fuente visual: www.flickr.com/photos/jhm0284/5813094884/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65082100, -0.88234700, '0101000020E6100000A62897C62F3CECBF67463F1A4ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14864455426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14864455426.webp', 'https://www.flickr.com/photos/zaragozaantigua/14864455426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22591, 'Calle C‚îú√≠diz 1978', 'J.L.O.G. Febrero 1978. Imagen de la calle de C‚îú√≠diz cuando se estaba procediendo al derribo del antiguo convento de las "Recogidas" (N‚î¨¬¨ S‚î¨¬¨ de la Misericordia de las Hermanas Recogidas), gestionado en su ‚îú‚ïëltima etapa (1971-1977) por Carmelitas Misioneras Teresianas, cuando fue vendido a la familia Parra. En este solar se levantar‚îú¬°a, despu‚îú¬Æs, el centro comercial "El Caracol", y las monjas se fueron a unas nuevas y lejanas instalaciones en el barrio de Casablanca. La fachada del convento llegaba hasta la plaza del Carmen, y llevaba casi un siglo albergando un colegio de ni‚îú‚ñías. Fuente: www.facebook.com/photo.php?fbid=725221827572843&set=g...', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65090100, -0.88405600, '0101000020E610000076A4FACE2F4AECBF83F755B950D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15772023001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15772023001.webp', 'https://www.flickr.com/photos/zaragozaantigua/15772023001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22609, 'Recogidas Calle C‚îú√≠diz 1978', 'La calle C‚îú√≠diz en el inicio del derribo del antiguo convento de las "Recogidas" (denominaci‚îú‚îÇn abreviada de "N‚î¨¬¨ S‚î¨¬¨ de la Misericordia de las Hermanas Recogidas"), gestionado en su ‚îú‚ïëltima etapa (1971-1977) por las MM. Carmelitas Misioneras Teresianas, hasta que vendieron la propiedad del suelo a un promotor inmobiliario local, y protagonizaron un nuevo cap‚îú¬°tulo de la "Operaci‚îú‚îÇn conventos y colegios privados", adquiriendo a cambio solares en v‚îú¬°rgenes y lejanas instalaciones en el barrio de Casablanca. En este solar, tras el derribo de lo que hubiera o hubiese, r‚îú√≠pidamente, ser‚îú√≠ construida una gran superficie comercial de lento nombre y notable popularidad, luego decreciente. Tras deambular por diversas ubicaciones de la ciudad, el Virrey Conde de Lemos hab‚îú¬°a posibilitado en 1647 el establecimiento en la antigua Morer‚îú¬°a, m‚îú√≠s despejada desde la expulsi‚îú‚îÇn de los moriscos en 1610, del Convento de las Recogidas de las MM. Carmelitas Terciarias Claustrales, con iglesia propia, como beaterio o "casa para el recogimiento de mujeres perdidas y escandalosas" (ergo mujeres prostituidas) sin votos, y estancia temporal. La entonces calle de Monz‚îú‚îÇn ser‚îú√≠ denominada, por ello, √î√á¬£de las Recogidas√î√á√ò. A finales del XVIII el convento fue reedificado en formas barroco-clasicistas, o neocl‚îú√≠sicas. En 1868 se instal‚îú‚îÇ aqu‚îú¬° un colegio de ni‚îú‚ñías, y en 1869 el Ayuntamiento proyect‚îú‚îÇ reformar la calle, entonces denominada del Parque, lo que supuso el derribo de sus fachadas, y la construcci‚îú‚îÇn de unas nuevas dise‚îú‚ñíadas por Fernando de Yarza, recayentes ya a la nueva calle C‚îú√≠diz, y a la plaza del Carmen. En 1964, las monjas alquilaron la parte que daba a esta plaza para el establecimiento de varias tiendas. En la imagen, perspectiva del antiguo convento, con la plaza del Carmen al fondo, precisamente por donde hab‚îú¬°a comenzado el derribo. El edificio de la iglesia estaba m‚îú√≠s pr‚îú‚îÇximo a esta plaza, y ya ha sido desmochado de su espada‚îú‚ñía y cubierta.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65090100, -0.88405600, '0101000020E610000076A4FACE2F4AECBF83F755B950D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19117945473.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19117945473.webp', 'https://www.flickr.com/photos/zaragozaantigua/19117945473/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22685, 'P.‚î¨‚ïë de la Independencia 1970', 'Interesante, colorista, e ins‚îú‚îÇlita imagen parcial del paseo de la Independencia, con visual del cartel anunciador del Teatro Argensola, que naciera como "Parisiana", pero que en 1938 fue "nacionalizado" en su denominaci‚îú‚îÇn, seg‚îú‚ïën la pol‚îú¬°tica nacionalista del momento. Esquinero con la calle de Zurita, a la izquierda, vio clausurada su vida art‚îú¬°stica en la prodigiosa d‚îú¬Æcada de los 80, y convertido en otro necesario pasaje comercial al uso. Por delante del teatro transita la composici‚îú‚îÇn 82+151 de la tranviaria l‚îú¬°nea 5 (Venecia-Delicias) traqueteando hacia la plaza de Huesca. Tras la clausura de la l‚îú¬°nea, a finales del a‚îú‚ñío siguiente, la unidad 82 fue instalada en 1974 en el Cabezo de Buenavista como biblioteca p‚îú‚ïëblica infantil, hasta terminar en el desguace, en 1980. Esta captura fue realizada por la australiana Lindsay Bridge un luminoso d‚îú¬°a de junio de 1970, en su paso por la ciudad durante su viaje a Europa de ese a‚îú‚ñío. Fuente visual: www.flickr.com/photos/intervene/1994927371/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65033400, -0.88246700, '0101000020E61000004F93196F2B3DECBF0ABDFE243ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26740874514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26740874514.webp', 'https://www.flickr.com/photos/zaragozaantigua/26740874514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22723, 'P.‚î¨‚ïë de la Independencia 1970', 'Imagen de la unidad 53 de los trolebuses urbanos, de la l‚îú¬°nea "Ciudad Jard‚îú¬°n", en el paseo de la Independencia, a punto de llegar a la terminal situada en la plaza de Santa Engracia. Se trata de uno de los BUT de dos pisos que llegaron de Londres la d‚îú¬Æcada anterior. A su derecha, la unidad 105 de la tranviaria l‚îú¬°nea "Venecia-Delicias", en direcci‚îú‚îÇn a la plaza de Huesca. De tel‚îú‚îÇn de fondo, el edificio de Correos y Tel‚îú¬Ægrafos, y a su lado, el de los Tel‚îú¬Æfonos. A la derecha, m‚îú¬°nima visual de la cobertura de ca‚îú‚ñíizo tras la que se estaba construyendo el gigante y nuevo n‚î¨‚ïë 1 de la plaza de Arag‚îú‚îÇn, donde estuviera ubicado el antiguo hotelito sede del Gobierno Civil. Fuente visual: Foto John Scragg, a trav‚îú¬Æs de www.forotrenes.com/', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64951900, -0.88354300, '0101000020E6100000E48233F8FB45ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30390389653.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30390389653.webp', 'https://www.flickr.com/photos/zaragozaantigua/30390389653/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22736, 'P‚î¨‚ïë Independencia 1972', 'Imagen capturada en el paseo de la Independencia, con vista parcial del tramo entre la calle de C‚îú√≠diz, a la derecha, fuera de plano, y el n‚î¨‚ïë 24, y centrada en moderno n‚î¨‚ïë 22 del paseo-autopista, uno de esos espec‚îú¬°menes recrecidos y acristalados que empezaban a marcar tendencia edilicia como s‚îú¬°mbolo de los nuevos tiempos La reiteraci‚îú‚îÇn de letras y pegatinas sobre los cristales, s‚îú¬°ntoma de reciente colocaci‚îú‚îÇn. A su derecha, el bloque del n‚î¨‚ïë 18-20, en el estilo neorregionalista de los 40''s; a su izquierda, una reliquia de los tiempos de la antigua calle de la Independencia, cuando alguien so‚îú‚ñí‚îú‚îÇ en voz alta que esto era la rue de Rivoli zaragozana. Unos a‚îú‚ñíos despu‚îú¬Æs este edificio ser‚îú¬°a remodelado durante las obras de habilitaci‚îú‚îÇn de una gran superficie comercial con forma de caracol. Fuente visual: foto Estudio Coyne, AHPZ.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65038700, -0.88312300, '0101000020E6100000950D6B2A8B42ECBF2D5F97E13FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31324849320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31324849320.webp', 'https://www.flickr.com/photos/zaragozaantigua/31324849320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22753, 'Pl. de Santa Engracia c.1975', 'Unidad de la l‚îú¬°nea de trolebuses Ciudad Jard‚îú¬°n, en su parada de inicio en la plaza Santa Engracia. Al fondo, el edificio de Correos. Este tipo de transporte ser‚îú√≠ retirado del servicio en octubre de 1975. Fuente visual: foto Arturo Burgos, en HA.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64931900, -0.88317800, '0101000020E6100000787E5182FE42ECBFF1D58EE21CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32674715024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32674715024.webp', 'https://www.flickr.com/photos/zaragozaantigua/32674715024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22871, 'P.‚î¨‚ïë de la Independencia c.1985', 'Edificios de la acera de los impares del paseo de la Independencia en la segunda mitad de la d‚îú¬Æcada de los a‚îú‚ñíos 80. Al fondo a la izquierda, la plaza de Espa‚îú‚ñía. Casi en primer t‚îú¬Ærmino, Correos y Telef‚îú‚îÇnica. Fuente: www.facebook.com/photo.php?fbid=1593276630900567&set=...', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.64932300, -0.88351400, '0101000020E610000051DCF126BF45ECBF33C51C041DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15794751131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15794751131.webp', 'https://www.flickr.com/photos/zaragozaantigua/15794751131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
